package networktool.filter;

import main.java.networktool.model.HostResult;

import java.util.ArrayList;
import java.util.List;

public final class HostResultFilter {

    private HostResultFilter() {}

    public static List<HostResult> filter(List<HostResult> found,
                                          String osFilter,
                                          String hostnameFilter) {
        boolean filterOs   = isActive(osFilter);
        boolean filterHost = isActive(hostnameFilter);

        List<HostResult> result = new ArrayList<>();
        for (HostResult r : found) {
            boolean osMatch   = !filterOs   || r.os.toLowerCase().contains(osFilter.toLowerCase());
            boolean hostMatch = !filterHost || matchesHostname(r, hostnameFilter);
            if (osMatch && hostMatch) result.add(r);
        }
        return result;
    }

    public static String buildLabel(String osFilter, String hostnameFilter) {
        if (!isActive(osFilter) && !isActive(hostnameFilter)) return "Alle Geräte";
        List<String> parts = new ArrayList<>();
        if (isActive(osFilter))       parts.add("OS: " + osFilter);
        if (isActive(hostnameFilter)) parts.add("Hostname: *" + hostnameFilter + "*");
        return "Filter — " + String.join(", ", parts);
    }

    private static boolean matchesHostname(HostResult r, String filter) {
        String pureName = r.hostname.contains(" [")
                ? r.hostname.substring(0, r.hostname.indexOf(" ["))
                : r.hostname;
        return !pureName.equals(r.ip)
                && pureName.toLowerCase().contains(filter.toLowerCase());
    }

    private static boolean isActive(String filter) {
        return filter != null && !filter.isEmpty() && !filter.equalsIgnoreCase("alle");
    }
}

package networktool.filter;

import networktool.model.HostResult;

import java.util.ArrayList;
import java.util.List;

public final class HostResultFilter {

    private HostResultFilter() {}

    public static List<HostResult> filter(List<HostResult> found,
                                          String osFilter,
                                          String hostnameFilter) {
        boolean filterOs   = isActive(osFilter);
        boolean filterHost = isActive(hostnameFilter);

        List<HostResult> result = new ArrayList<>();
        for (HostResult r : found) {
            boolean osMatch   = !filterOs   || r.os.toLowerCase().contains(osFilter.toLowerCase());
            boolean hostMatch = !filterHost || matchesHostname(r, hostnameFilter);
            if (osMatch && hostMatch) result.add(r);
        }
        return result;
    }

    public static String buildLabel(String osFilter, String hostnameFilter) {
        if (!isActive(osFilter) && !isActive(hostnameFilter)) return "Alle Geräte";
        List<String> parts = new ArrayList<>();
        if (isActive(osFilter))       parts.add("OS: " + osFilter);
        if (isActive(hostnameFilter)) parts.add("Hostname: *" + hostnameFilter + "*");
        return "Filter — " + String.join(", ", parts);
    }

    private static boolean matchesHostname(HostResult r, String filter) {
        String pureName = r.hostname.contains(" [")
                ? r.hostname.substring(0, r.hostname.indexOf(" ["))
                : r.hostname;
        return !pureName.equals(r.ip)
                && pureName.toLowerCase().contains(filter.toLowerCase());
    }

    private static boolean isActive(String filter) {
        return filter != null && !filter.isEmpty() && !filter.equalsIgnoreCase("alle");
    }
}

package main.java.networktool.filter;

import main.java.networktool.gui.GUI;
import main.java.networktool.model.HostResult;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

/**
 * Gibt eine Liste von {@link HostResult}s aus –
 * im GUI-Modus als Tabelle, im CLI-Modus als formatierte Konsolenausgabe.
 */
public final class HostResultPrinter {

    private HostResultPrinter() {}

    private static final String CLI_HEADER_FORMAT = "%-15s %-45s %s%n";
    private static final String CLI_SEPARATOR     = "-".repeat(80);

    public static void print(List<HostResult> list, String label) {
        if (GUI.isGuiActive()) {
            GUI.instance().showHostTable(list, label);
            return;
        }
        printCli(list, label);
    }

    private static void printCli(List<HostResult> list, String label) {
        List<HostResult> sorted = new ArrayList<>(list);  // <-- mutable Kopie
        sorted.sort(Comparator.comparingInt(r -> ipToInt(r.ip)));
        System.out.println("\n=== " + label + " (" + sorted.size() + " Gerät(e)) ===");
        System.out.printf(CLI_HEADER_FORMAT, "IP", "Hostname [MAC]", "OS / Gerät");
        System.out.println(CLI_SEPARATOR);
        for (HostResult r : sorted) {
            System.out.printf(CLI_HEADER_FORMAT, r.ip, r.hostname, r.os);
        }
    }

    private static int ipToInt(String ip) {
        String[] parts = ip.split("\\.");
        int result = 0;
        for (String p : parts) {
            try { result = (result << 8) | Integer.parseInt(p.trim()); }
            catch (NumberFormatException ignored) {}
        }
        return result;
    }
}

