package networktool.gui;

import main.java.networktool.logic.analysis.OuiUpdater;
import main.java.networktool.logic.messaging.MessageSender;
import main.java.networktool.security.LoginDialog;
import main.java.networktool.storage.NetworkStore;
import main.java.networktool.model.HostResult;
import main.java.networktool.model.ScanResult;
import main.java.networktool.security.AuditLogger;
import main.java.networktool.security.SecurityMonitor;
import main.java.networktool.security.UserAuth;

import javax.swing.*;
import java.awt.*;
import java.awt.event.*;
import java.util.List;
import java.util.logging.Logger;
import java.util.logging.Level;

/**
 * Haupt-Fenster der Anwendung.
 *
 * Besonderheiten:
 *  - searchBar-Feld MUSS vor savedHostsPanel deklariert/initialisiert werden
 *  - Fenster öffnet sich auf dem Monitor des Login-Dialogs
 *  - Admin-Check für Menü 11 (Fremdnetz) und 23 (Audit-Log) in handleMenuClick
 *  - GuiSearchBar wird ausschließlich über savedHostsPanel.show() aktiviert
 *    und bei jedem anderen Menüklick über searchBar.hide() deaktiviert
 *  - Smooth Theme-Wechsel via Swing-Timer (3 Repaints à 16 ms)
 */
public class GUI extends JFrame {

    private static GUI INSTANCE;
    private static final Logger LOGGER = Logger.getLogger(GUI.class.getName());
    public static boolean isGuiActive() {
        return INSTANCE != null && INSTANCE.isDisplayable();
    }
    public static GUI     instance()    { return INSTANCE; }

    /** Monitor auf dem der Login-Dialog angezeigt wurde. */
    private static GraphicsDevice loginMonitor = null;
    public static void setLoginMonitor(GraphicsDevice device) { loginMonitor = device; }

    // !! Reihenfolge der Deklaration = Reihenfolge der Initialisierung !!
    // searchBar MUSS vor savedHostsPanel stehen – wird als Parameter übergeben.
    private final GuiSearchBar       searchBar;
    private final GuiOutputPanel     outputPanel;
    private final GuiProgressBar     progressBar;
    private final GuiStatusBar       statusBar;
    private final GuiInputPanel      inputPanel;
    private final GuiTableRenderer   tableRenderer;
    private final GuiMenuHandler     menuHandler;
    private final GuiContextMenu     contextMenu;
    private final GuiSavedHostsPanel savedHostsPanel;

    public GUI() {
        super("NetTool //");
        INSTANCE = this;

        setDefaultCloseOperation(DO_NOTHING_ON_CLOSE);
        setMinimumSize(new Dimension(860, 520));
        getContentPane().setBackground(GuiTheme.BG);
        setLayout(new BorderLayout());

        // Initialisierungsreihenfolge beachten!
        searchBar       = new GuiSearchBar();
        outputPanel     = new GuiOutputPanel();
        progressBar     = new GuiProgressBar();
        statusBar       = new GuiStatusBar();
        inputPanel      = new GuiInputPanel(statusBar.getLabel(), outputPanel);
        tableRenderer   = new GuiTableRenderer(outputPanel);
        menuHandler     = new GuiMenuHandler(inputPanel, outputPanel, tableRenderer, statusBar);
        contextMenu     = new GuiContextMenu(menuHandler, outputPanel);
        savedHostsPanel = new GuiSavedHostsPanel(menuHandler, outputPanel, contextMenu, searchBar);

        tableRenderer.setContextMenu(contextMenu);
        menuHandler.setSavedHostsPanel(savedHostsPanel);

        outputPanel.redirectStreams();
        buildLayout();
        installKeyboardShortcuts();
        installWindowClose();

        enterFullscreen();
        AppIcon.apply(this);
        setVisible(true);
        outputPanel.printBanner();

        // Benutzer-Info
        String user   = UserAuth.getInstance().getCurrentUser();
        boolean admin = UserAuth.getInstance().isAdmin();
        if (user != null) {
            String roleLabel = admin ? "  [admin]" : "  [user]";
            outputPanel.appendText("  Eingeloggt als: " + user + roleLabel + "\n\n",
                    admin ? GuiTheme.ACCENT : GuiTheme.ACCENT2);
        }

        MessageSender.startListener();
        OuiUpdater.initAsync(NetworkStore.getInstance().dataDir);

        // SecurityMonitor nach 5 s passiv starten
        new Thread(() -> {
            try {
                Thread.sleep(5_000);
            } catch (InterruptedException interruptedException) {
                LOGGER.log(Level.FINE, "SecurityMonitor initialization interrupted", interruptedException);
                Thread.currentThread().interrupt();
            }
            if (!SecurityMonitor.getInstance().isActive())
                SecurityMonitor.getInstance().start("");
        }, "SecurityMonitor-Init").start();
    }

    // ── Layout ────────────────────────────────────────────────────────────

    private void buildLayout() {
        add(GuiSidebar.build(
                this::handleMenuClick,
                menuHandler::cancel,
                this::restart,
                this::toggleTheme,
                menuHandler::isRunning
        ), BorderLayout.WEST);
        add(buildMainPanel(),       BorderLayout.CENTER);
        add(statusBar.buildPanel(), BorderLayout.SOUTH);
    }

    /**
     * Zentraler Menü-Dispatch mit Admin-Check und SearchBar-Steuerung.
     *
     * Regeln:
     *  "09" → savedHostsPanel.show() ruft searchBar.show() intern
     *  alle anderen → searchBar.hide()
     *  "11" Fremdnetz → nur Admins
     *  "23" Audit-Log → nur Admins
     *  "30" Privatsphäre → GuiPrivacyPanel
     */
    private void handleMenuClick(String id) {
        // Admin-Only
        if ("11".equals(id) && !UserAuth.getInstance().isAdmin()) {
            outputPanel.appendText("  ✕ Fremdnetz-Scanner: nur für Admins.\n", GuiTheme.WARN);
            return;
        }
        if ("23".equals(id)) {
            if (!UserAuth.getInstance().isAdmin()) {
                outputPanel.appendText("  ✕ Audit-Log: nur für Admins.\n", GuiTheme.WARN);
                return;
            }
            AuditLogger.getInstance().log("MENU", "23-AuditLog");
            GuiAuditPanel.show(outputPanel);
            return;
        }
        if ("30".equals(id)) {
            AuditLogger.getInstance().log("MENU", "30-Privacy");
            GuiPrivacyPanel.show(outputPanel);
            searchBar.hide(); // sicherheitshalber
            return;
        }

        // SearchBar: bei allen Menüpunkten außer 09 ausblenden.
        // Bei 09 übernimmt savedHostsPanel.show() die Aktivierung.
        if (!"09".equals(id)) {
            searchBar.hide();
        }

        menuHandler.handle(id);
    }

    private JPanel buildMainPanel() {
        JPanel bottom = new JPanel(new BorderLayout());
        bottom.setBackground(GuiTheme.PANEL_BG);
        bottom.add(progressBar.getPanel(),  BorderLayout.NORTH);
        bottom.add(inputPanel.buildPanel(), BorderLayout.SOUTH);

        JPanel centerArea = new JPanel(new BorderLayout());
        centerArea.setBackground(GuiTheme.BG);
        // searchBar ist standardmäßig unsichtbar; liegt trotzdem im Layout
        centerArea.add(searchBar,                     BorderLayout.NORTH);
        centerArea.add(outputPanel.buildScrollPane(), BorderLayout.CENTER);

        JPanel main = new JPanel(new BorderLayout());
        main.setBackground(GuiTheme.BG);
        main.add(outputPanel.buildTopBar(), BorderLayout.NORTH);
        main.add(centerArea,                BorderLayout.CENTER);
        main.add(bottom,                    BorderLayout.SOUTH);
        return main;
    }

    // ── Keyboard Shortcuts ────────────────────────────────────────────────

    private void installKeyboardShortcuts() {
        JRootPane root = getRootPane();
        InputMap  im   = root.getInputMap(JComponent.WHEN_IN_FOCUSED_WINDOW);
        ActionMap am   = root.getActionMap();

        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_Q, InputEvent.CTRL_DOWN_MASK), "quit");
        am.put("quit", new AbstractAction() {
            public void actionPerformed(ActionEvent e) { confirmQuit(); }
        });
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_R, InputEvent.CTRL_DOWN_MASK), "restart");
        am.put("restart", new AbstractAction() {
            public void actionPerformed(ActionEvent e) { restart(); }
        });
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_A, InputEvent.CTRL_DOWN_MASK), "cancel");
        am.put("cancel", new AbstractAction() {
            public void actionPerformed(ActionEvent e) { menuHandler.cancel(); }
        });
        // Ctrl+F: SearchBar toggle – nur wenn SavedHosts aktiv (searchBar sichtbar)
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_F, InputEvent.CTRL_DOWN_MASK), "search");
        am.put("search", new AbstractAction() {
            public void actionPerformed(ActionEvent e) {
                if (searchBar.isVisible()) {
                    if (searchBar.isSearchVisible()) searchBar.hide();
                    else searchBar.show();
                }
            }
        });
    }

    // ── Window-Close ─────────────────────────────────────────────────────

    private void installWindowClose() {
        addWindowListener(new WindowAdapter() {
            @Override public void windowClosing(WindowEvent e) { confirmQuit(); }
        });
    }

    private void confirmQuit() {
        if (menuHandler.isRunning()) {
            int c = JOptionPane.showConfirmDialog(this,
                    "<html><b>Ein Scan läuft gerade.</b><br>Wirklich beenden?</html>",
                    "Beenden bestätigen", JOptionPane.YES_NO_OPTION, JOptionPane.WARNING_MESSAGE);
            if (c != JOptionPane.YES_OPTION) return;
        }
        AuditLogger.getInstance().log("APP_EXIT", UserAuth.getInstance().getCurrentUser());
        System.exit(0);
    }

    // ── Theme Toggle (smooth) ─────────────────────────────────────────────

    private void toggleTheme() {
        GuiTheme.toggleTheme();
        GuiTheme.applyToStatics();
        String msg = GuiTheme.isDark() ? "Dark Mode" : "Light Mode";
        getContentPane().setBackground(GuiTheme.BG);

        // 3 Repaints im 16-ms-Takt → smooth, kein hartes Flackern
        int[] count = {0};
        Timer t = new Timer(16, null);
        t.addActionListener(e -> {
            SwingUtilities.updateComponentTreeUI(this);
            repaint(); revalidate();
            if (++count[0] >= 3) t.stop();
        });
        t.start();

        outputPanel.appendText("  " + msg + " aktiviert.\n", GuiTheme.ACCENT);
        statusBar.set("Theme: " + msg, GuiTheme.ACCENT2);
        AuditLogger.getInstance().log("THEME_TOGGLE", msg);
    }

    // ── Öffentliche API ───────────────────────────────────────────────────

    public void showProgress(int total)  { progressBar.showProgress(total); }
    public void updateProgress(int done) { progressBar.updateProgress(done); }

    public void showHostTable(List<HostResult> rows, String title) {
        tableRenderer.showHostTable(rows, title);
    }
    public void showScanTable(List<ScanResult> rows) {
        tableRenderer.showScanTable(rows);
    }

    public void appendText(String text, Color color) { outputPanel.appendText(text, color); }
    public void setStatus(String msg, Color color)   { statusBar.set(msg, color); }
    public JTextPane getOutputPane()                 { return outputPanel.getOutputPane(); }

    // ── Neustart ─────────────────────────────────────────────────────────

    private void restart() {
        AuditLogger.getInstance().log("APP_RESTART", UserAuth.getInstance().getCurrentUser());
        SecurityMonitor.getInstance().stop();
        loginMonitor = getGraphicsConfiguration().getDevice();
        dispose();
        INSTANCE = null;
        SwingUtilities.invokeLater(() -> {
            try { UIManager.setLookAndFeel(UIManager.getSystemLookAndFeelClassName()); }
            catch (Exception ignored) {}
            boolean ok = LoginDialog.show(UserAuth.getInstance());
            if (!ok) System.exit(0);
            AuditLogger.getInstance().log("LOGIN_AFTER_RESTART",
                    UserAuth.getInstance().getCurrentUser());
            new GUI();
        });
    }

    // ── Fullscreen auf richtigem Monitor ──────────────────────────────────

    private void enterFullscreen() {
        setUndecorated(true);
        GraphicsDevice target = (loginMonitor != null)
                ? loginMonitor
                : GraphicsEnvironment.getLocalGraphicsEnvironment().getDefaultScreenDevice();
        setBounds(target.getDefaultConfiguration().getBounds());
        setExtendedState(JFrame.MAXIMIZED_BOTH);
    }

    public static void launch() {
        SwingUtilities.invokeLater(() -> {
            try { UIManager.setLookAndFeel(UIManager.getSystemLookAndFeelClassName()); }
            catch (Exception ignored) {}
            new GUI();
        });
    }
}

package networktool.gui;

import networktool.logic.analysis.OuiUpdater;
import networktool.logic.messaging.MessageSender;
import networktool.security.LoginDialog;
import networktool.storage.NetworkStore;
import networktool.model.HostResult;
import networktool.model.ScanResult;
import networktool.security.AuditLogger;
import networktool.security.SecurityMonitor;
import networktool.security.UserAuth;

import javax.swing.*;
import java.awt.*;
import java.awt.event.*;
import java.util.List;
import java.util.logging.Logger;
import java.util.logging.Level;

/**
 * Haupt-Fenster der Anwendung.
 *
 * Besonderheiten:
 *  - searchBar-Feld MUSS vor savedHostsPanel deklariert/initialisiert werden
 *  - Fenster öffnet sich auf dem Monitor des Login-Dialogs
 *  - Admin-Check für Menü 11 (Fremdnetz) und 23 (Audit-Log) in handleMenuClick
 *  - GuiSearchBar wird ausschließlich über savedHostsPanel.show() aktiviert
 *    und bei jedem anderen Menüklick über searchBar.hide() deaktiviert
 *  - Smooth Theme-Wechsel via Swing-Timer (3 Repaints à 16 ms)
 */
public class GUI extends JFrame {

    private static GUI INSTANCE;
    private static final Logger LOGGER = Logger.getLogger(GUI.class.getName());
    public static boolean isGuiActive() {
        return INSTANCE != null && INSTANCE.isDisplayable();
    }
    public static GUI     instance()    { return INSTANCE; }

    /** Monitor auf dem der Login-Dialog angezeigt wurde. */
    private static GraphicsDevice loginMonitor = null;
    public static void setLoginMonitor(GraphicsDevice device) { loginMonitor = device; }

    // !! Reihenfolge der Deklaration = Reihenfolge der Initialisierung !!
    // searchBar MUSS vor savedHostsPanel stehen – wird als Parameter übergeben.
    private final GuiSearchBar       searchBar;
    private final GuiOutputPanel     outputPanel;
    private final GuiProgressBar     progressBar;
    private final GuiStatusBar       statusBar;
    private final GuiInputPanel      inputPanel;
    private final GuiTableRenderer   tableRenderer;
    private final GuiMenuHandler     menuHandler;
    private final GuiContextMenu     contextMenu;
    private final GuiSavedHostsPanel savedHostsPanel;

    public GUI() {
        super("NetTool //");
        INSTANCE = this;

        setDefaultCloseOperation(DO_NOTHING_ON_CLOSE);
        setMinimumSize(new Dimension(860, 520));
        getContentPane().setBackground(GuiTheme.BG);
        setLayout(new BorderLayout());

        // Initialisierungsreihenfolge beachten!
        searchBar       = new GuiSearchBar();
        outputPanel     = new GuiOutputPanel();
        progressBar     = new GuiProgressBar();
        statusBar       = new GuiStatusBar();
        inputPanel      = new GuiInputPanel(statusBar.getLabel(), outputPanel);
        tableRenderer   = new GuiTableRenderer(outputPanel);
        menuHandler     = new GuiMenuHandler(inputPanel, outputPanel, tableRenderer, statusBar);
        contextMenu     = new GuiContextMenu(menuHandler, outputPanel);
        savedHostsPanel = new GuiSavedHostsPanel(menuHandler, outputPanel, contextMenu, searchBar);

        tableRenderer.setContextMenu(contextMenu);
        menuHandler.setSavedHostsPanel(savedHostsPanel);

        outputPanel.redirectStreams();
        buildLayout();
        installKeyboardShortcuts();
        installWindowClose();

        enterFullscreen();
        AppIcon.apply(this);
        setVisible(true);
        outputPanel.printBanner();

        // Benutzer-Info
        String user   = UserAuth.getInstance().getCurrentUser();
        boolean admin = UserAuth.getInstance().isAdmin();
        if (user != null) {
            String roleLabel = admin ? "  [admin]" : "  [user]";
            outputPanel.appendText("  Eingeloggt als: " + user + roleLabel + "\n\n",
                    admin ? GuiTheme.ACCENT : GuiTheme.ACCENT2);
        }

        MessageSender.startListener();
        OuiUpdater.initAsync(NetworkStore.getInstance().dataDir);

        // SecurityMonitor nach 5 s passiv starten
        new Thread(() -> {
            try {
                Thread.sleep(5_000);
            } catch (InterruptedException interruptedException) {
                LOGGER.log(Level.FINE, "SecurityMonitor initialization interrupted", interruptedException);
                Thread.currentThread().interrupt();
            }
            if (!SecurityMonitor.getInstance().isActive())
                SecurityMonitor.getInstance().start("");
        }, "SecurityMonitor-Init").start();
    }

    // ── Layout ────────────────────────────────────────────────────────────

    private void buildLayout() {
        add(GuiSidebar.build(
                this::handleMenuClick,
                menuHandler::cancel,
                this::restart,
                this::toggleTheme,
                menuHandler::isRunning
        ), BorderLayout.WEST);
        add(buildMainPanel(),       BorderLayout.CENTER);
        add(statusBar.buildPanel(), BorderLayout.SOUTH);
    }

    /**
     * Zentraler Menü-Dispatch mit Admin-Check und SearchBar-Steuerung.
     *
     * Regeln:
     *  "09" → savedHostsPanel.show() ruft searchBar.show() intern
     *  alle anderen → searchBar.hide()
     *  "11" Fremdnetz → nur Admins
     *  "23" Audit-Log → nur Admins
     *  "30" Privatsphäre → GuiPrivacyPanel
     */
    private void handleMenuClick(String id) {
        // Admin-Only
        if ("11".equals(id) && !UserAuth.getInstance().isAdmin()) {
            outputPanel.appendText("  ✕ Fremdnetz-Scanner: nur für Admins.\n", GuiTheme.WARN);
            return;
        }
        if ("23".equals(id)) {
            if (!UserAuth.getInstance().isAdmin()) {
                outputPanel.appendText("  ✕ Audit-Log: nur für Admins.\n", GuiTheme.WARN);
                return;
            }
            AuditLogger.getInstance().log("MENU", "23-AuditLog");
            GuiAuditPanel.show(outputPanel);
            return;
        }
        if ("30".equals(id)) {
            AuditLogger.getInstance().log("MENU", "30-Privacy");
            GuiPrivacyPanel.show(outputPanel);
            searchBar.hide(); // sicherheitshalber
            return;
        }

        // SearchBar: bei allen Menüpunkten außer 09 ausblenden.
        // Bei 09 übernimmt savedHostsPanel.show() die Aktivierung.
        if (!"09".equals(id)) {
            searchBar.hide();
        }

        menuHandler.handle(id);
    }

    private JPanel buildMainPanel() {
        JPanel bottom = new JPanel(new BorderLayout());
        bottom.setBackground(GuiTheme.PANEL_BG);
        bottom.add(progressBar.getPanel(),  BorderLayout.NORTH);
        bottom.add(inputPanel.buildPanel(), BorderLayout.SOUTH);

        JPanel centerArea = new JPanel(new BorderLayout());
        centerArea.setBackground(GuiTheme.BG);
        // searchBar ist standardmäßig unsichtbar; liegt trotzdem im Layout
        centerArea.add(searchBar,                     BorderLayout.NORTH);
        centerArea.add(outputPanel.buildScrollPane(), BorderLayout.CENTER);

        JPanel main = new JPanel(new BorderLayout());
        main.setBackground(GuiTheme.BG);
        main.add(outputPanel.buildTopBar(), BorderLayout.NORTH);
        main.add(centerArea,                BorderLayout.CENTER);
        main.add(bottom,                    BorderLayout.SOUTH);
        return main;
    }

    // ── Keyboard Shortcuts ────────────────────────────────────────────────

    private void installKeyboardShortcuts() {
        JRootPane root = getRootPane();
        InputMap  im   = root.getInputMap(JComponent.WHEN_IN_FOCUSED_WINDOW);
        ActionMap am   = root.getActionMap();

        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_Q, InputEvent.CTRL_DOWN_MASK), "quit");
        am.put("quit", new AbstractAction() {
            public void actionPerformed(ActionEvent e) { confirmQuit(); }
        });
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_R, InputEvent.CTRL_DOWN_MASK), "restart");
        am.put("restart", new AbstractAction() {
            public void actionPerformed(ActionEvent e) { restart(); }
        });
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_A, InputEvent.CTRL_DOWN_MASK), "cancel");
        am.put("cancel", new AbstractAction() {
            public void actionPerformed(ActionEvent e) { menuHandler.cancel(); }
        });
        // Ctrl+F: SearchBar toggle – nur wenn SavedHosts aktiv (searchBar sichtbar)
        im.put(KeyStroke.getKeyStroke(KeyEvent.VK_F, InputEvent.CTRL_DOWN_MASK), "search");
        am.put("search", new AbstractAction() {
            public void actionPerformed(ActionEvent e) {
                if (searchBar.isVisible()) {
                    if (searchBar.isSearchVisible()) searchBar.hide();
                    else searchBar.show();
                }
            }
        });
    }

    // ── Window-Close ─────────────────────────────────────────────────────

    private void installWindowClose() {
        addWindowListener(new WindowAdapter() {
            @Override public void windowClosing(WindowEvent e) { confirmQuit(); }
        });
    }

    private void confirmQuit() {
        if (menuHandler.isRunning()) {
            int c = JOptionPane.showConfirmDialog(this,
                    "<html><b>Ein Scan läuft gerade.</b><br>Wirklich beenden?</html>",
                    "Beenden bestätigen", JOptionPane.YES_NO_OPTION, JOptionPane.WARNING_MESSAGE);
            if (c != JOptionPane.YES_OPTION) return;
        }
        AuditLogger.getInstance().log("APP_EXIT", UserAuth.getInstance().getCurrentUser());
        System.exit(0);
    }

    // ── Theme Toggle (smooth) ─────────────────────────────────────────────

    private void toggleTheme() {
        GuiTheme.toggleTheme();
        GuiTheme.applyToStatics();
        String msg = GuiTheme.isDark() ? "Dark Mode" : "Light Mode";
        getContentPane().setBackground(GuiTheme.BG);

        // 3 Repaints im 16-ms-Takt → smooth, kein hartes Flackern
        int[] count = {0};
        Timer t = new Timer(16, null);
        t.addActionListener(e -> {
            SwingUtilities.updateComponentTreeUI(this);
            repaint(); revalidate();
            if (++count[0] >= 3) t.stop();
        });
        t.start();

        outputPanel.appendText("  " + msg + " aktiviert.\n", GuiTheme.ACCENT);
        statusBar.set("Theme: " + msg, GuiTheme.ACCENT2);
        AuditLogger.getInstance().log("THEME_TOGGLE", msg);
    }

    // ── Öffentliche API ───────────────────────────────────────────────────

    public void showProgress(int total)  { progressBar.showProgress(total); }
    public void updateProgress(int done) { progressBar.updateProgress(done); }

    public void showHostTable(List<HostResult> rows, String title) {
        tableRenderer.showHostTable(rows, title);
    }
    public void showScanTable(List<ScanResult> rows) {
        tableRenderer.showScanTable(rows);
    }

    public void appendText(String text, Color color) { outputPanel.appendText(text, color); }
    public void setStatus(String msg, Color color)   { statusBar.set(msg, color); }
    public JTextPane getOutputPane()                 { return outputPanel.getOutputPane(); }

    // ── Neustart ─────────────────────────────────────────────────────────

    private void restart() {
        AuditLogger.getInstance().log("APP_RESTART", UserAuth.getInstance().getCurrentUser());
        SecurityMonitor.getInstance().stop();
        loginMonitor = getGraphicsConfiguration().getDevice();
        dispose();
        INSTANCE = null;
        SwingUtilities.invokeLater(() -> {
            try { UIManager.setLookAndFeel(UIManager.getSystemLookAndFeelClassName()); }
            catch (Exception ignored) {}
            boolean ok = LoginDialog.show(UserAuth.getInstance());
            if (!ok) System.exit(0);
            AuditLogger.getInstance().log("LOGIN_AFTER_RESTART",
                    UserAuth.getInstance().getCurrentUser());
            new GUI();
        });
    }

    // ── Fullscreen auf richtigem Monitor ──────────────────────────────────

    private void enterFullscreen() {
        setUndecorated(true);
        GraphicsDevice target = (loginMonitor != null)
                ? loginMonitor
                : GraphicsEnvironment.getLocalGraphicsEnvironment().getDefaultScreenDevice();
        setBounds(target.getDefaultConfiguration().getBounds());
        setExtendedState(JFrame.MAXIMIZED_BOTH);
    }

    public static void launch() {
        SwingUtilities.invokeLater(() -> {
            try { UIManager.setLookAndFeel(UIManager.getSystemLookAndFeelClassName()); }
            catch (Exception ignored) {}
            new GUI();
        });
    }
}

package networktool.gui;

import javax.swing.*;
import javax.swing.border.*;
import java.awt.*;

import static main.java.networktool.gui.GuiTheme.*;

/** Legende mit Aktions-Codes und Menü-IDs für den Audit-Log-Viewer. */
final class GuiAuditLegend {

    private GuiAuditLegend() {}

    private static final String[][] ACTION_LEGEND = {
            {"LOGIN",             "Erfolgreiche Anmeldung"},
            {"LOGIN_FAILED",      "Fehlgeschlagener Login"},
            {"LOGOUT",            "Abmeldung"},
            {"USER_CREATED",      "Neuer Benutzer angelegt"},
            {"APP_START/EXIT",    "Programm gestartet / beendet"},
            {"APP_RESTART",       "Neustart"},
            {"MENU",              "Menüpunkt geklickt (Detail = Menü-ID)"},
            {"SCAN / DIAGNOSE",   "Netzwerk-Scan / IP-Diagnose"},
            {"SECURITY_ALERT",    "Sicherheitswarnung"},
            {"EXPORT / IMPORT",   "Datenexport / -import"},
            {"CANCEL",            "Laufenden Scan abgebrochen"},
            {"AUDIT_LOG_CLEARED", "Audit-Log manuell geleert"},
    };

    private static final String[][] MENU_ID_LEGEND = {
            {"01", "Minimale Netzwerkinfo"},   {"02", "Vollständige Netzwerkinfo"},
            {"03", "IP-Diagnose"},             {"04", "File-Server starten"},
            {"05", "Datei senden"},            {"06", "CIDR-Scan"},
            {"07", "Filter-Scan"},             {"08", "Nachricht senden"},
            {"09", "Gespeicherte Hosts"},      {"10", "Hops & Routen"},
            {"11", "Fremdnetz-Scanner"},       {"12", "Scan-Profile"},
            {"13", "Scan-Delta"},              {"14", "Scheduler"},
            {"15", "Bandwidth-Test"},          {"16", "Dauerping"},
            {"17", "Sicherheitsmonitor"},      {"18", "Export / Import"},
            {"19", "Benachrichtigungs-Verlauf"},{"20", "Netzwerk-Karte"},
            {"21", "Port-Liste"},              {"22", "Scan-Verlauf"},
            {"23", "Audit-Log"},               {"30", "Privatsphäre / VPN"},
    };

    static JPanel build(Color panBg) {
        JPanel wrapper = new JPanel(new BorderLayout());
        wrapper.setBackground(panBg);
        wrapper.setBorder(new MatteBorder(0, 1, 1, 1, BORDER));

        JButton toggleBtn = new JButton("▶  Aktions-Codes & Menü-IDs");
        toggleBtn.setFont(new Font("JetBrains Mono", Font.BOLD, 10));
        toggleBtn.setForeground(FG_DIM);
        toggleBtn.setBackground(panBg);
        toggleBtn.setBorderPainted(false);
        toggleBtn.setContentAreaFilled(false);
        toggleBtn.setFocusPainted(false);
        toggleBtn.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        toggleBtn.setBorder(new EmptyBorder(4, 10, 4, 10));
        toggleBtn.setHorizontalAlignment(SwingConstants.LEFT);

        JPanel content = new JPanel(new GridLayout(1, 2, 20, 0));
        content.setBackground(panBg);
        content.setBorder(new EmptyBorder(4, 14, 8, 14));
        content.setVisible(false);
        content.add(buildGrid(panBg, "Aktions-Codes", ACTION_LEGEND, ACCENT));
        content.add(buildGrid(panBg, "Menü-IDs",      MENU_ID_LEGEND, INFO));

        JLabel hint = new JLabel("  Rotation ab 200.000 Einträgen  ·  Logs bleiben über Neustarts erhalten");
        hint.setFont(new Font("JetBrains Mono", Font.PLAIN, 9));
        hint.setForeground(FG_DIM);
        hint.setBorder(new EmptyBorder(2, 10, 4, 10));

        toggleBtn.addActionListener(e -> {
            boolean open = content.isVisible();
            content.setVisible(!open);
            toggleBtn.setText((open ? "▶" : "▼") + "  Aktions-Codes & Menü-IDs");
            wrapper.revalidate(); wrapper.repaint();
        });

        wrapper.add(toggleBtn, BorderLayout.NORTH);
        wrapper.add(content,   BorderLayout.CENTER);
        wrapper.add(hint,      BorderLayout.SOUTH);
        return wrapper;
    }

    private static JPanel buildGrid(Color panBg, String title, String[][] rows, Color keyColor) {
        JPanel p = new JPanel(new GridLayout(0, 2, 10, 1));
        p.setBackground(panBg);
        JLabel titleLbl = new JLabel(title);
        titleLbl.setFont(new Font("JetBrains Mono", Font.BOLD, 10));
        titleLbl.setForeground(ACCENT);
        p.add(titleLbl);
        p.add(new JLabel(""));
        for (String[] row : rows) {
            JLabel key = new JLabel(row[0]);
            key.setFont(new Font("JetBrains Mono", Font.BOLD, 10));
            key.setForeground(keyColor);
            JLabel desc = new JLabel(row[1]);
            desc.setFont(new Font("JetBrains Mono", Font.PLAIN, 10));
            desc.setForeground(FG_DIM);
            p.add(key);
            p.add(desc);
        }
        return p;
    }
}

package networktool.gui;

import javax.swing.*;
import javax.swing.border.*;
import java.awt.*;

import static networktool.gui.GuiTheme.*;

/** Legende mit Aktions-Codes und Menü-IDs für den Audit-Log-Viewer. */
final class GuiAuditLegend {

    private GuiAuditLegend() {}

    private static final String[][] ACTION_LEGEND = {
            {"LOGIN",             "Erfolgreiche Anmeldung"},
            {"LOGIN_FAILED",      "Fehlgeschlagener Login"},
            {"LOGOUT",            "Abmeldung"},
            {"USER_CREATED",      "Neuer Benutzer angelegt"},
            {"APP_START/EXIT",    "Programm gestartet / beendet"},
            {"APP_RESTART",       "Neustart"},
            {"MENU",              "Menüpunkt geklickt (Detail = Menü-ID)"},
            {"SCAN / DIAGNOSE",   "Netzwerk-Scan / IP-Diagnose"},
            {"SECURITY_ALERT",    "Sicherheitswarnung"},
            {"EXPORT / IMPORT",   "Datenexport / -import"},
            {"CANCEL",            "Laufenden Scan abgebrochen"},
            {"AUDIT_LOG_CLEARED", "Audit-Log manuell geleert"},
    };

    private static final String[][] MENU_ID_LEGEND = {
            {"01", "Minimale Netzwerkinfo"},   {"02", "Vollständige Netzwerkinfo"},
            {"03", "IP-Diagnose"},             {"04", "File-Server starten"},
            {"05", "Datei senden"},            {"06", "CIDR-Scan"},
            {"07", "Filter-Scan"},             {"08", "Nachricht senden"},
            {"09", "Gespeicherte Hosts"},      {"10", "Hops & Routen"},
            {"11", "Fremdnetz-Scanner"},       {"12", "Scan-Profile"},
            {"13", "Scan-Delta"},              {"14", "Scheduler"},
            {"15", "Bandwidth-Test"},          {"16", "Dauerping"},
            {"17", "Sicherheitsmonitor"},      {"18", "Export / Import"},
            {"19", "Benachrichtigungs-Verlauf"},{"20", "Netzwerk-Karte"},
            {"21", "Port-Liste"},              {"22", "Scan-Verlauf"},
            {"23", "Audit-Log"},               {"30", "Privatsphäre / VPN"},
    };

    static JPanel build(Color panBg) {
        JPanel wrapper = new JPanel(new BorderLayout());
        wrapper.setBackground(panBg);
        wrapper.setBorder(new MatteBorder(0, 1, 1, 1, BORDER));

        JButton toggleBtn = new JButton("▶  Aktions-Codes & Menü-IDs");
        toggleBtn.setFont(new Font("JetBrains Mono", Font.BOLD, 10));
        toggleBtn.setForeground(FG_DIM);
        toggleBtn.setBackground(panBg);
        toggleBtn.setBorderPainted(false);
        toggleBtn.setContentAreaFilled(false);
        toggleBtn.setFocusPainted(false);
        toggleBtn.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        toggleBtn.setBorder(new EmptyBorder(4, 10, 4, 10));
        toggleBtn.setHorizontalAlignment(SwingConstants.LEFT);

        JPanel content = new JPanel(new GridLayout(1, 2, 20, 0));
        content.setBackground(panBg);
        content.setBorder(new EmptyBorder(4, 14, 8, 14));
        content.setVisible(false);
        content.add(buildGrid(panBg, "Aktions-Codes", ACTION_LEGEND, ACCENT));
        content.add(buildGrid(panBg, "Menü-IDs",      MENU_ID_LEGEND, INFO));

        JLabel hint = new JLabel("  Rotation ab 200.000 Einträgen  ·  Logs bleiben über Neustarts erhalten");
        hint.setFont(new Font("JetBrains Mono", Font.PLAIN, 9));
        hint.setForeground(FG_DIM);
        hint.setBorder(new EmptyBorder(2, 10, 4, 10));

        toggleBtn.addActionListener(e -> {
            boolean open = content.isVisible();
            content.setVisible(!open);
            toggleBtn.setText((open ? "▶" : "▼") + "  Aktions-Codes & Menü-IDs");
            wrapper.revalidate(); wrapper.repaint();
        });

        wrapper.add(toggleBtn, BorderLayout.NORTH);
        wrapper.add(content,   BorderLayout.CENTER);
        wrapper.add(hint,      BorderLayout.SOUTH);
        return wrapper;
    }

    private static JPanel buildGrid(Color panBg, String title, String[][] rows, Color keyColor) {
        JPanel p = new JPanel(new GridLayout(0, 2, 10, 1));
        p.setBackground(panBg);
        JLabel titleLbl = new JLabel(title);
        titleLbl.setFont(new Font("JetBrains Mono", Font.BOLD, 10));
        titleLbl.setForeground(ACCENT);
        p.add(titleLbl);
        p.add(new JLabel(""));
        for (String[] row : rows) {
            JLabel key = new JLabel(row[0]);
            key.setFont(new Font("JetBrains Mono", Font.BOLD, 10));
            key.setForeground(keyColor);
            JLabel desc = new JLabel(row[1]);
            desc.setFont(new Font("JetBrains Mono", Font.PLAIN, 10));
            desc.setForeground(FG_DIM);
            p.add(key);
            p.add(desc);
        }
        return p;
    }
}

package main.java.networktool.gui;

import main.java.networktool.security.AuditLogEntry;
import main.java.networktool.security.AuditLogger;

import javax.swing.*;
import javax.swing.border.*;
import javax.swing.table.*;
import java.awt.*;
import java.awt.event.*;
import java.util.List;

import static main.java.networktool.gui.GuiTheme.*;

/** Audit-Log-Viewer (Menü-ID "23", nur Admins). */
public final class GuiAuditPanel {

    private GuiAuditPanel() {}

    static final int MAX_DETAIL = 55;

    private record ToolbarRefs(
            JPanel panel, JTextField filterField,
            JLabel countLbl, JButton refreshBtn, JButton clearBtn
    ) {}

    public static void show(GuiOutputPanel output) {
        SwingUtilities.invokeLater(() -> {
            output.appendText("\n★ Audit-Log\n\n", ACCENT);
            embedPanel(output);
        });
    }

    private static void embedPanel(GuiOutputPanel output) {
        Color bg    = GuiTheme.isDark() ? new Color(0x08, 0x0B, 0x09) : new Color(0xF4, 0xF2, 0xEE);
        Color panBg = GuiTheme.isDark() ? new Color(0x0F, 0x13, 0x10) : new Color(0xE8, 0xE6, 0xE0);

        JPanel outer = new JPanel(new BorderLayout(0, 0));
        outer.setBackground(bg);

        ToolbarRefs refs = buildToolbar(panBg, bg);
        outer.add(refs.panel(), BorderLayout.NORTH);

        DefaultTableModel model = GuiAuditTable.createModel();
        JTable table = GuiAuditTable.buildTable(model);
        TableRowSorter<DefaultTableModel> sorter = new TableRowSorter<>(model);
        table.setRowSorter(sorter);

        JScrollPane sp = new JScrollPane(table,
                JScrollPane.VERTICAL_SCROLLBAR_AS_NEEDED,
                JScrollPane.HORIZONTAL_SCROLLBAR_NEVER);
        sp.setBackground(GuiTheme.rowEven());
        sp.getViewport().setBackground(GuiTheme.rowEven());
        sp.setBorder(new LineBorder(BORDER, 1));
        sp.setPreferredSize(new Dimension(0, 320));
        outer.add(sp, BorderLayout.CENTER);
        outer.add(GuiAuditLegend.build(panBg), BorderLayout.SOUTH);

        wireFilter(refs, sorter, table);
        wireButtons(refs, model, outer);
        new Thread(() -> reload(model, outer, refs), "AuditLoad").start();

        JTextPane pane = output.getOutputPane();
        pane.setEditable(true);
        pane.setCaretPosition(pane.getStyledDocument().getLength());
        pane.insertComponent(outer);
        pane.setEditable(false);
        output.appendText("\n\n", FG);
    }

    static void reload(DefaultTableModel model, JPanel outer, ToolbarRefs refs) {
        List<AuditLogEntry> entries = AuditLogger.getInstance().readRecent(2000);
        if (!outer.isDisplayable()) return;
        SwingUtilities.invokeLater(() -> {
            if (!outer.isDisplayable()) return;
            model.setRowCount(0);
            for (AuditLogEntry e : entries) {
                String shortDetail = e.detail().length() > MAX_DETAIL
                        ? e.detail().substring(0, MAX_DETAIL) + "…" : e.detail();
                model.addRow(new Object[]{e.timestamp(), e.user(), e.action(), shortDetail, e.detail()});
            }
            refs.countLbl().setText(model.getRowCount() + " Einträge");
        });
    }

    private static void wireFilter(ToolbarRefs refs, TableRowSorter<DefaultTableModel> sorter, JTable table) {
        refs.filterField().getDocument().addDocumentListener(docListener(() -> {
            String q = refs.filterField().getText().trim();
            sorter.setRowFilter(q.isEmpty() ? null : RowFilter.regexFilter("(?i)" + q));
            refs.countLbl().setText(table.getRowCount() + " Einträge");
        }));
    }

    private static void wireButtons(ToolbarRefs refs, DefaultTableModel model, JPanel outer) {
        refs.refreshBtn().addActionListener(e ->
                new Thread(() -> reload(model, outer, refs), "AuditLoad").start());
        refs.clearBtn().addActionListener(e -> {
            int ok = JOptionPane.showConfirmDialog(null, "Audit-Log wirklich leeren?",
                    "Bestätigung", JOptionPane.YES_NO_OPTION, JOptionPane.WARNING_MESSAGE);
            if (ok != JOptionPane.YES_OPTION) return;
            try {
                AuditLogger.getInstance().clear();
                model.setRowCount(0);
                refs.countLbl().setText("0 Einträge");
            } catch (SecurityException ex) {
                JOptionPane.showMessageDialog(null, "Keine Berechtigung: " + ex.getMessage(),
                        "Fehler", JOptionPane.ERROR_MESSAGE);
            }
        });
    }

    private static ToolbarRefs buildToolbar(Color panBg, Color bg) {
        JPanel toolbar = new JPanel(new BorderLayout(8, 0));
        toolbar.setBackground(panBg);
        toolbar.setBorder(new CompoundBorder(
                new MatteBorder(1, 1, 0, 1, BORDER), new EmptyBorder(5, 10, 5, 10)));

        JTextField filterField = new JTextField();
        filterField.setFont(MONO_XS);
        filterField.setForeground(FG);
        filterField.setBackground(bg);
        filterField.setCaretColor(ACCENT);
        filterField.setBorder(new CompoundBorder(new LineBorder(BORDER, 1), new EmptyBorder(2, 6, 2, 6)));
        filterField.putClientProperty("JTextField.placeholderText", "Filter…");

        JLabel countLbl = new JLabel("–");
        countLbl.setFont(MONO_XS);
        countLbl.setForeground(FG_DIM);
        countLbl.setBorder(new EmptyBorder(0, 8, 0, 0));

        JPanel left = new JPanel(new BorderLayout(4, 0));
        left.setOpaque(false);
        left.add(filterField, BorderLayout.CENTER);
        left.add(countLbl,    BorderLayout.EAST);

        JButton refreshBtn = toolBtn("↻", ACCENT);
        JButton clearBtn   = toolBtn("", WARN);

        JPanel right = new JPanel(new FlowLayout(FlowLayout.RIGHT, 4, 0));
        right.setOpaque(false);
        right.add(refreshBtn);
        right.add(clearBtn);

        toolbar.add(left,  BorderLayout.CENTER);
        toolbar.add(right, BorderLayout.EAST);
        return new ToolbarRefs(toolbar, filterField, countLbl, refreshBtn, clearBtn);
    }

    static JButton toolBtn(String text, Color fg) {
        JButton b = new JButton(text);
        b.setFont(new Font("Segoe UI Emoji", Font.BOLD, 12));
        b.setForeground(fg);
        b.setBackground(BTN_BG);
        b.setBorder(new CompoundBorder(new LineBorder(fg.darker(), 1), new EmptyBorder(2, 7, 2, 7)));
        b.setFocusPainted(false);
        b.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        b.addMouseListener(new MouseAdapter() {
            public void mouseEntered(MouseEvent e) { b.setBackground(BTN_HOV); }
            public void mouseExited(MouseEvent e)  { b.setBackground(BTN_BG); }
        });
        return b;
    }

    static javax.swing.event.DocumentListener docListener(Runnable r) {
        return new javax.swing.event.DocumentListener() {
            public void insertUpdate(javax.swing.event.DocumentEvent e)  { r.run(); }
            public void removeUpdate(javax.swing.event.DocumentEvent e)  { r.run(); }
            public void changedUpdate(javax.swing.event.DocumentEvent e) {}
        };
    }
}

