        for (int i = 0; i < 4 && i < cm.getColumnCount(); i++) {
            cm.getColumn(i).setPreferredWidth(WIDTHS[i]);
            if (i < 3) { cm.getColumn(i).setMinWidth(WIDTHS[i]); cm.getColumn(i).setMaxWidth(WIDTHS[i]); }
        }
        if (cm.getColumnCount() > 4) {
            TableColumn hidden = cm.getColumn(4);
            hidden.setMinWidth(0); hidden.setMaxWidth(0); hidden.setWidth(0);
        }
        TableConfig.styleHeader(table.getTableHeader());
        table.getTableHeader().setReorderingAllowed(false);
    }

    private static Color colColor(int col, Object val) {
        return switch (col) {
            case 0 -> FG_DIM;
            case 1 -> ACCENT;
            case 2 -> actionColor(val != null ? val.toString() : "");
            default -> FG;
        };
    }

    static Color actionColor(String action) {
        if (action == null) return FG;
        String a = action.toUpperCase().trim();

        // Angriffsereignisse → rot
        if (a.contains("SPOOF") || a.contains("POISON") || a.contains("ROGUE")) return WARN;
        if (a.contains("FAIL")  || a.contains("BLOCK"))                          return WARN;
        if (a.contains("ALERT"))                                                  return WARN;

        // Monitor-Ereignisse → orange (vor generischen Prefix-Checks)
        if (a.startsWith("SECURITY_MONITOR") || a.startsWith("ARP_MONITOR")
                || a.startsWith("PORT_MONITOR"))                        return new Color(0xFF, 0xA0, 0x30);

        // Generische Security/ARP → orange
        if (a.startsWith("SECURITY") || a.startsWith("ARP"))           return new Color(0xFF, 0xA0, 0x30);

        if (a.startsWith("SCAN") || a.startsWith("DIAGNOSE") || a.startsWith("CIDR")) return INFO;
        if (a.startsWith("LOGIN"))                                       return ACCENT2;
        if (a.startsWith("EXPORT") || a.startsWith("IMPORT"))           return new Color(0xD0, 0xC0, 0x60);
        if (a.startsWith("USER") || a.startsWith("APP_START"))          return ACCENT;
        return FG;
    }
}

package main.java.networktool.logic.analysis;

import java.util.List;
import java.util.Objects;

/**
 * Schnelle OS-Erkennungs-Pipeline.
 * Reihenfolge: kein I/O zuerst, TCP zuletzt.
 *
 *  1. Hostname  – kein Netzwerk-IO
 *  2. MAC/OUI   – nur ARP-Cache
 *  3. Banner    – TCP: SSH/HTTP/SMB/FTP/HTTPS
 *  4. UDP       – NetBIOS/mDNS/SNMP
 *  5. mDNS-Unicast direkt an Host
 *  6. Ports     – teuerster Schritt
 *  7. TTL       – Fallback ohne TCP
 */
final class OsDetectionPipeline {

    private OsDetectionPipeline() {}

    static OsDetector.OsResult run(String ip) {
        System.out.println("  [OS-Detect] " + ip);
        OsSignature best = null;

        best = merge(best, step("Hostname", hostname(ip)));
        if (hit(best, 75)) return result(best);

        best = merge(best, step("MAC/OUI", macOui(ip)));
        if (hit(best, 65)) return result(best);

        best = merge(best, step("Banner", OsBannerAnalyzer.analyze(ip)));
        if (hit(best, 85)) return result(best);

        best = merge(best, step("UDP", OsProbeUdp.probe(ip)));
        if (hit(best, 80)) return result(best);

        best = merge(best, step("mDNS", mdnsUnicast(ip)));
        if (hit(best, 75)) return result(best);

        best = merge(best, step("Ports", OsDetectorPorts.detectWithSignature(ip)));
        if (hit(best, 60)) return result(best);

        best = merge(best, step("TTL", ttlNoTcp(ip)));

        return best != null ? result(best)
                : new OsDetector.OsResult("Unbekannt", OsDetector.Confidence.NIEDRIG, "—");
    }

    // ── Probe-Methoden ────────────────────────────────────────────────────

    private static OsSignature hostname(String ip) {
        String h = resolveHostname(ip);
        if (h == null) return null;
        String os = OsDetectorHostname.classify(h.toLowerCase());
        return os != null ? OsSignature.of(os, 75, "Hostname") : null;
    }

    private static OsSignature macOui(String ip) {
        String mac = OsDetectorArp.getMacFromArp(ip);
        if (mac == null) return null;
        String vendor = OuiDatabase.lookup(mac);
        return vendor != null ? OsSignature.of(vendor, 65, "OUI") : null;
    }

    private static OsSignature mdnsUnicast(String ip) {
        List<MdnsDiscovery.ServiceRecord> records = MdnsDiscovery.queryHost(ip);
        return records.stream()
                .map(MdnsDiscovery.ServiceRecord::guessOs)
                .filter(Objects::nonNull)
                .findFirst()
                .map(os -> OsSignature.of(os, 72, "mDNS-Unicast"))
                .orElse(null);
    }

    private static OsSignature ttlNoTcp(String ip) {
        String mac = OsDetectorArp.getMacFromArp(ip);
        int    ttl = OsDetectorArp.getTtl(ip);
        if (ttl <= 0 && mac == null) return null;
        String fp  = OsFingerprint.resolveNoTcp(ip, ttl, mac);
        return fp != null ? OsSignature.of(fp, 40, "TTL=" + ttl) : null;
    }

    // ── Hilfsmethoden ─────────────────────────────────────────────────────

    private static OsSignature step(String name, OsSignature sig) {
        return OsDetectionLogger.tryStep(name, sig);
    }

    private static OsSignature merge(OsSignature a, OsSignature b) {
        return OsSignature.best(a, b);
    }

    private static boolean hit(OsSignature s, int threshold) {
        return s != null && s.score >= threshold;
    }

    private static OsDetector.OsResult result(OsSignature s) {
        return new OsDetector.OsResult(s.os, s.toConfidence(), s.method);
    }

    private static String resolveHostname(String ip) {
        String[] out = {null};
        Thread t = new Thread(() -> {
            try {
                String h = java.net.InetAddress.getByName(ip).getCanonicalHostName();
                if (!h.equals(ip)) out[0] = h;
            } catch (Exception ignored) {}
        });
        t.setDaemon(true);
        t.start();
        try { t.join(600); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        return out[0];
    }
}

package main.java.networktool.logic.analysis;

import java.util.List;
import java.util.Objects;
import java.util.logging.Logger;
import java.util.logging.Level;

/**
 * Schnelle OS-Erkennungs-Pipeline.
 * Reihenfolge: kein I/O zuerst, TCP zuletzt.
 *
 *  1. Hostname  – kein Netzwerk-IO
 *  2. MAC/OUI   – nur ARP-Cache
 *  3. Banner    – TCP: SSH/HTTP/SMB/FTP/HTTPS
 *  4. UDP       – NetBIOS/mDNS/SNMP
 *  5. mDNS-Unicast direkt an Host
 *  6. Ports     – teuerster Schritt
 *  7. TTL       – Fallback ohne TCP
 */
final class OsDetectionPipeline {

    private OsDetectionPipeline() {}

    private static final Logger LOGGER = Logger.getLogger(OsDetectionPipeline.class.getName());

    static OsDetector.OsResult run(String ip) {
        System.out.println("  [OS-Detect] " + ip);
        OsSignature best = null;

        best = merge(best, step("Hostname", hostname(ip)));
        if (hit(best, 75)) return result(best);

        best = merge(best, step("MAC/OUI", macOui(ip)));
        if (hit(best, 65)) return result(best);

        best = merge(best, step("Banner", OsBannerAnalyzer.analyze(ip)));
        if (hit(best, 85)) return result(best);

        best = merge(best, step("UDP", OsProbeUdp.probe(ip)));
        if (hit(best, 80)) return result(best);

        best = merge(best, step("mDNS", mdnsUnicast(ip)));
        if (hit(best, 75)) return result(best);

        best = merge(best, step("Ports", OsDetectorPorts.detectWithSignature(ip)));
        if (hit(best, 60)) return result(best);

        best = merge(best, step("TTL", ttlNoTcp(ip)));

        return best != null ? result(best)
                : new OsDetector.OsResult("Unbekannt", OsDetector.Confidence.NIEDRIG, "—");
    }

    // ── Probe-Methoden ────────────────────────────────────────────────────

    private static OsSignature hostname(String ip) {
        String h = resolveHostname(ip);
        if (h == null) return null;
        String os = OsDetectorHostname.classify(h.toLowerCase());
        return os != null ? OsSignature.of(os, 75, "Hostname") : null;
    }

    private static OsSignature macOui(String ip) {
        String mac = OsDetectorArp.getMacFromArp(ip);
        if (mac == null) return null;
        String vendor = OuiDatabase.lookup(mac);
        return vendor != null ? OsSignature.of(vendor, 65, "OUI") : null;
    }

    private static OsSignature mdnsUnicast(String ip) {
        List<MdnsDiscovery.ServiceRecord> records = MdnsDiscovery.queryHost(ip);
        return records.stream()
                .map(MdnsDiscovery.ServiceRecord::guessOs)
                .filter(Objects::nonNull)
                .findFirst()
                .map(os -> OsSignature.of(os, 72, "mDNS-Unicast"))
                .orElse(null);
    }

    private static OsSignature ttlNoTcp(String ip) {
        String mac = OsDetectorArp.getMacFromArp(ip);
        int    ttl = OsDetectorArp.getTtl(ip);
        if (ttl <= 0 && mac == null) return null;
        String fp  = OsFingerprint.resolveNoTcp(ip, ttl, mac);
        return fp != null ? OsSignature.of(fp, 40, "TTL=" + ttl) : null;
    }

    // ── Hilfsmethoden ─────────────────────────────────────────────────────

    private static OsSignature step(String name, OsSignature sig) {
        return OsDetectionLogger.tryStep(name, sig);
    }

    private static OsSignature merge(OsSignature a, OsSignature b) {
        return OsSignature.best(a, b);
    }

    private static boolean hit(OsSignature s, int threshold) {
        return s != null && s.score >= threshold;
    }

    private static OsDetector.OsResult result(OsSignature s) {
        return new OsDetector.OsResult(s.os, s.toConfidence(), s.method);
    }

    private static String resolveHostname(String ip) {
        String[] out = {null};
        Thread t = new Thread(() -> {
            try {
                String h = java.net.InetAddress.getByName(ip).getCanonicalHostName();
                if (!h.equals(ip)) out[0] = h;
            } catch (java.net.UnknownHostException uhe) {
                LOGGER.log(Level.FINE, "Unable to resolve hostname for IP " + ip, uhe);
            } catch (Exception exception) {
                LOGGER.log(Level.WARNING, "Error resolving hostname for " + ip, exception);
            }
        });
        t.setDaemon(true);
        t.start();
        try { 
            t.join(600); 
        } catch (InterruptedException interruptedException) { 
            LOGGER.log(Level.FINE, "Thread.join interrupted", interruptedException);
            Thread.currentThread().interrupt(); 
        }
        return out[0];
    }
}

package main.java.networktool.logic.messaging;

import main.java.networktool.gui.notification.LocalToast;
import main.java.networktool.gui.notification.NotificationListener;
import main.java.networktool.logic.analysis.OsDetector;

/**
 * Sendet Benachrichtigungen an Netzwerk-Hosts.
 * Delegiert an {@link MessageDelivery} für die eigentliche Übertragung.
 *
 * Reihenfolge:
 *  1. ntfy.sh (falls Topic angegeben)  → Handy / PC mit App
 *  2. NetTool-Listener Port 9999       → NetTool auf Ziel läuft
 *  3. WinRM                            → Windows-Ziel mit PSRemoting
 *  4. SSH                              → Linux / macOS mit Key-Auth
 *  Fallback: {@link LocalToast} + Hinweise
 */
public final class MessageSender {

    private MessageSender() {}

    /** Port des eingebauten TCP-Listeners. */
    public static final int NETTOOL_LISTENER_PORT = 9999;

    public static void send(String targetIp, String message, String ntfyTopic) {
        printHeader(targetIp, message, ntfyTopic);
        try {
            boolean ntfySent = false;

            // ntfy immer zuerst (Topic angegeben) – zählt als erfolgreich gesendet
            if (!ntfyTopic.isBlank()) {
                MessageDelivery.tryNtfy(ntfyTopic, message);
                ntfySent = true;
            }

            if (!java.net.InetAddress.getByName(targetIp)
                    .isReachable(MessageDelivery.TIMEOUT_MS)) {
                if (!ntfySent)
                    System.out.println("  Ziel nicht erreichbar – nur ntfy-Kanal möglich.");
                System.out.println("\n═══════════════════════════════════════════════");
                return;
            }

            String os = OsDetector.detect(targetIp).toLowerCase();
            System.out.println("  OS-Heuristik : " + OsDetector.detect(targetIp));
            System.out.println();

            boolean localSent = MessageDelivery.tryListener(targetIp, message);
            if (!localSent && os.contains("windows")) localSent = MessageDelivery.tryWinRM(targetIp, message);
            if (!localSent && isUnix(os)) localSent = MessageDelivery.trySsh(targetIp, message, isMac(os));
            if (!localSent && !ntfySent) printFallbackHints(targetIp);

        } catch (Exception e) {
            System.err.println("  Fehler: " + e.getMessage());
        }
        System.out.println("\n═══════════════════════════════════════════════");
    }

    public static void send(String targetIp, String message) {
        send(targetIp, message, "");
    }

    /** Zeigt Toast auf eigenem PC. Delegiert an {@link LocalToast}. */
    public static void showLocalToast(String title, String message) {
        LocalToast.show(title, message);
    }

    /** Startet eingehenden Listener. Delegiert an {@link NotificationListener}. */
    public static void startListener() {
        NotificationListener.start();
    }

    /** Stoppt den Listener (nur für Tests). */
    public static void stopListener() {
        NotificationListener.stop();
    }

    private static boolean isUnix(String os) {
        return os.contains("linux") || os.contains("unix")
                || os.contains("macos") || os.contains("apple");
    }
    private static boolean isMac(String os) {
        return os.contains("macos") || os.contains("apple");
    }

    private static void printHeader(String ip, String msg, String topic) {
        System.out.println("\n╔══════════════════════════════════════════════╗");
        System.out.println("║           Nachricht senden                   ║");
        System.out.println("╚══════════════════════════════════════════════╝");
        System.out.println("  Ziel     : " + ip);
        if (!topic.isBlank()) System.out.println("  ntfy-Topic: " + topic);
        System.out.println("  Nachricht: " + msg);
        System.out.println();
    }

    private static void printFallbackHints(String ip) {
        System.out.println("  Kein Übertragungsweg verfügbar. Optionen:");
        System.out.println("  • NetTool auf Ziel öffnen (Port 9999 öffnet automatisch)");
        System.out.println("  • WinRM: Enable-PSRemoting -Force  (Admin auf Windows-Ziel)");
        System.out.println("  • SSH-Key: ssh-copy-id user@" + ip + "  (Linux/Mac-Ziel)");
        System.out.println("  • ntfy-App installieren + Topic angeben (Handy)");
        LocalToast.show("NetTool – nicht gesendet an " + ip, "Kein Übertragungsweg");
    }
}

