package main.java.networktool.logic.scan;

import java.io.*;
import java.net.*;
import java.nio.charset.StandardCharsets;
import java.util.*;
import java.util.concurrent.*;

/**
 * Erkennt Netzwerk-Rollen (DNS-Server, DHCP-Server, mDNS) durch aktives Probing.
 *
 * Strategie je Protokoll:
 *  DNS  → UDP-Query (A-Record "example.com") + TCP-Port-Check
 *  DHCP → UDP-Discover (Broadcast-fähig, Port 67) + Antwort-Listening
 *  mDNS → UDP-Query auf 224.0.0.251:5353
 *  NTP  → UDP-Request auf Port 123
 *
 * Ergebnisse werden für die Karten-Laufzeit gecacht.
 */
public class MapTrafficObserver {

    public enum NodeRole { DNS_SERVER, DHCP_SERVER, MDNS_NODE, NTP_SERVER, UNKNOWN }

    private static final int TIMEOUT_MS   = 600;
    private static final int DNS_PORT     = 53;
    private static final int DHCP_PORT    = 67;
    private static final int MDNS_PORT    = 5353;
    private static final int NTP_PORT     = 123;

    private final Map<String, NodeRole> roles = new ConcurrentHashMap<>();

    // ── Public API ────────────────────────────────────────────────────────

    public void probe(String ip) {
        NodeRole role = detect(ip);
        if (role != NodeRole.UNKNOWN) roles.put(ip, role);
    }

    public void probeAll(List<String> ips) {
        ExecutorService exec = Executors.newFixedThreadPool(
                Math.min(ips.size(), 16));
        ips.forEach(ip -> exec.submit(() -> probe(ip)));
        exec.shutdown();
        try { exec.awaitTermination(TIMEOUT_MS * 2L + 500, TimeUnit.MILLISECONDS); }
        catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    public NodeRole getRole(String ip) {
        return roles.getOrDefault(ip, NodeRole.UNKNOWN);
    }

    public Map<String, NodeRole> getAllRoles() {
        return Collections.unmodifiableMap(roles);
    }

    public void clear() { roles.clear(); }

    // ── Detection ─────────────────────────────────────────────────────────

    private NodeRole detect(String ip) {
        if (isDnsServer(ip))  return NodeRole.DNS_SERVER;
        if (isDhcpServer(ip)) return NodeRole.DHCP_SERVER;
        if (isMdnsNode(ip))   return NodeRole.MDNS_NODE;
        if (isNtpServer(ip))  return NodeRole.NTP_SERVER;
        return NodeRole.UNKNOWN;
    }

    /**
     * DNS-Erkennung:
     *  1. TCP-Port 53 offen (schnell)
     *  2. UDP DNS-Query auf "version.bind" → antwortet nur echter DNS-Server
     */
    private boolean isDnsServer(String ip) {
        if (isTcpOpen(ip, DNS_PORT)) return true;
        return sendDnsQuery(ip);
    }

    /**
     * DHCP: UDP-Port 67.
     * Direktes Verbinden auf UDP 67 ist auf den meisten OS blockiert,
     * daher prüfen wir ob der Host auf einen simplen UDP-Paket antwortet.
     */
    private boolean isDhcpServer(String ip) {
        return isUdpResponsive(ip, DHCP_PORT, buildDhcpDiscover());
    }

    /**
     * mDNS: Multicast 224.0.0.251:5353.
     * Wir senden eine mDNS-Query und prüfen ob eine Antwort kommt.
     * Fallback: TCP/UDP 5353 offen.
     */
    private boolean isMdnsNode(String ip) {
        if (isTcpOpen(ip, MDNS_PORT)) return true;
        return sendMdnsQuery(ip);
    }

    private boolean isNtpServer(String ip) {
        return isUdpResponsive(ip, NTP_PORT, buildNtpRequest());
    }

    // ── DNS Query (UDP) ───────────────────────────────────────────────────

    /**
     * Sendet einen minimalen DNS-Query für "version.bind" (CHAOS/TXT).
     * Echter DNS-Server antwortet, andere Geräte antworten nicht.
     */
    private boolean sendDnsQuery(String ip) {
        try (DatagramSocket socket = new DatagramSocket()) {
            socket.setSoTimeout(TIMEOUT_MS);
            byte[] query = buildDnsQuery("version.bind", true);
            InetAddress addr = InetAddress.getByName(ip);
            socket.send(new DatagramPacket(query, query.length, addr, DNS_PORT));
            byte[] buf = new byte[512];
            socket.receive(new DatagramPacket(buf, buf.length));
            // Antwort empfangen → DNS-Server bestätigt
            return true;
        } catch (SocketTimeoutException e) {
            return false; // kein DNS-Server
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Minimaler DNS-Query.
     * @param name  Hostname (z.B. "version.bind")
     * @param chaos true = CHAOS-Klasse, false = IN-Klasse
     */
    private byte[] buildDnsQuery(String name, boolean chaos) {
        // ID=0x1337, QR=0 (Query), Opcode=0, RD=1
        byte[] header = {
                0x13, 0x37,  // ID
                0x01, 0x00,  // Flags: RD=1
                0x00, 0x01,  // QDCOUNT=1
                0x00, 0x00,  // ANCOUNT=0
                0x00, 0x00,  // NSCOUNT=0
                0x00, 0x00   // ARCOUNT=0
        };

        // Name kodieren
        String[] labels = name.split("\\.");
        ByteArrayOutputStream nameBytes = new ByteArrayOutputStream();
        for (String label : labels) {
            byte[] lb = label.getBytes(StandardCharsets.US_ASCII);
            nameBytes.write(lb.length);
            nameBytes.write(lb, 0, lb.length);
        }
        nameBytes.write(0x00); // End-of-Name

        // QTYPE=TXT(16), QCLASS=CHAOS(3) oder IN(1)
        byte qclass = chaos ? (byte) 0x03 : (byte) 0x01;
        byte[] qtype = {0x00, 0x10, 0x00, qclass};

        ByteArrayOutputStream out = new ByteArrayOutputStream();
        out.write(header, 0, header.length);
        byte[] nb = nameBytes.toByteArray();
        out.write(nb, 0, nb.length);
        out.write(qtype, 0, qtype.length);
        return out.toByteArray();
    }

    // ── DHCP Discover (UDP) ───────────────────────────────────────────────

    /**
     * Minimales DHCP-Discover-Paket.
     * Wird an den spezifischen Host gesendet (kein Broadcast) um Kollisionen zu vermeiden.
     */
    private byte[] buildDhcpDiscover() {
        byte[] pkt = new byte[300];
        pkt[0]  = 0x01; // BOOTREQUEST
        pkt[1]  = 0x01; // Ethernet
        pkt[2]  = 0x06; // Hardware address length
        pkt[3]  = 0x00; // Hops
        // XID (random)
        new Random().nextBytes(new byte[4]);
        pkt[4] = 0x39; pkt[5] = 0x03; pkt[6] = (byte)0xF3; pkt[7] = 0x26;
        // Flags: broadcast
        pkt[10] = (byte)0x80; pkt[11] = 0x00;
        // Magic cookie
        pkt[236] = 0x63; pkt[237] = (byte)0x82; pkt[238] = 0x53; pkt[239] = 0x63;
        // Option 53: DHCP Discover
        pkt[240] = 0x35; pkt[241] = 0x01; pkt[242] = 0x01;
        // End option
        pkt[243] = (byte)0xFF;
        return pkt;
    }

    // ── mDNS Query (UDP Multicast) ────────────────────────────────────────

    private boolean sendMdnsQuery(String ip) {
        try (MulticastSocket socket = new MulticastSocket()) {
            socket.setSoTimeout(TIMEOUT_MS);
            socket.setTimeToLive(1);
            byte[] query = buildDnsQuery("_services._dns-sd._udp.local", false);
            InetAddress mdnsGroup = InetAddress.getByName("224.0.0.251");
            socket.send(new DatagramPacket(query, query.length, mdnsGroup, MDNS_PORT));
            byte[] buf = new byte[512];
            DatagramPacket response = new DatagramPacket(buf, buf.length);
            socket.receive(response);
            // Prüfen ob Antwort von der gesuchten IP kommt
            return ip.equals(response.getAddress().getHostAddress());
        } catch (Exception e) {
            return false;
        }
    }

    // ── NTP Request (UDP) ─────────────────────────────────────────────────

    private byte[] buildNtpRequest() {
        byte[] pkt = new byte[48];
        pkt[0] = 0x1B; // LI=0, VN=3, Mode=3 (Client)
        return pkt;
    }

    // ── Generic UDP probe ─────────────────────────────────────────────────

    private boolean isUdpResponsive(String ip, int port, byte[] payload) {
        try (DatagramSocket socket = new DatagramSocket()) {
            socket.setSoTimeout(TIMEOUT_MS);
            InetAddress addr = InetAddress.getByName(ip);
            socket.send(new DatagramPacket(payload, payload.length, addr, port));
            byte[] buf = new byte[512];
            socket.receive(new DatagramPacket(buf, buf.length));
            return true;
        } catch (SocketTimeoutException e) {
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    // ── TCP helper ────────────────────────────────────────────────────────

    private boolean isTcpOpen(String ip, int port) {
        try (Socket s = new Socket()) {
            s.connect(new InetSocketAddress(ip, port), TIMEOUT_MS);
            return true;
        } catch (Exception e) {
            return false;
        }
    }
}

package networktool.logic.scan;

import java.io.*;
import java.net.*;
import java.nio.charset.StandardCharsets;
import java.util.*;
import java.util.concurrent.*;

/**
 * Erkennt Netzwerk-Rollen (DNS-Server, DHCP-Server, mDNS) durch aktives Probing.
 *
 * Strategie je Protokoll:
 *  DNS  → UDP-Query (A-Record "example.com") + TCP-Port-Check
 *  DHCP → UDP-Discover (Broadcast-fähig, Port 67) + Antwort-Listening
 *  mDNS → UDP-Query auf 224.0.0.251:5353
 *  NTP  → UDP-Request auf Port 123
 *
 * Ergebnisse werden für die Karten-Laufzeit gecacht.
 */
public class MapTrafficObserver {

    public enum NodeRole { DNS_SERVER, DHCP_SERVER, MDNS_NODE, NTP_SERVER, UNKNOWN }

    private static final int TIMEOUT_MS   = 600;
    private static final int DNS_PORT     = 53;
    private static final int DHCP_PORT    = 67;
    private static final int MDNS_PORT    = 5353;
    private static final int NTP_PORT     = 123;

    private final Map<String, NodeRole> roles = new ConcurrentHashMap<>();

    // ── Public API ────────────────────────────────────────────────────────

    public void probe(String ip) {
        NodeRole role = detect(ip);
        if (role != NodeRole.UNKNOWN) roles.put(ip, role);
    }

    public void probeAll(List<String> ips) {
        ExecutorService exec = Executors.newFixedThreadPool(
                Math.min(ips.size(), 16));
        ips.forEach(ip -> exec.submit(() -> probe(ip)));
        exec.shutdown();
        try { exec.awaitTermination(TIMEOUT_MS * 2L + 500, TimeUnit.MILLISECONDS); }
        catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    public NodeRole getRole(String ip) {
        return roles.getOrDefault(ip, NodeRole.UNKNOWN);
    }

    public Map<String, NodeRole> getAllRoles() {
        return Collections.unmodifiableMap(roles);
    }

    public void clear() { roles.clear(); }

    // ── Detection ─────────────────────────────────────────────────────────

    private NodeRole detect(String ip) {
        if (isDnsServer(ip))  return NodeRole.DNS_SERVER;
        if (isDhcpServer(ip)) return NodeRole.DHCP_SERVER;
        if (isMdnsNode(ip))   return NodeRole.MDNS_NODE;
        if (isNtpServer(ip))  return NodeRole.NTP_SERVER;
        return NodeRole.UNKNOWN;
    }

    /**
     * DNS-Erkennung:
     *  1. TCP-Port 53 offen (schnell)
     *  2. UDP DNS-Query auf "version.bind" → antwortet nur echter DNS-Server
     */
    private boolean isDnsServer(String ip) {
        if (isTcpOpen(ip, DNS_PORT)) return true;
        return sendDnsQuery(ip);
    }

    /**
     * DHCP: UDP-Port 67.
     * Direktes Verbinden auf UDP 67 ist auf den meisten OS blockiert,
     * daher prüfen wir ob der Host auf einen simplen UDP-Paket antwortet.
     */
    private boolean isDhcpServer(String ip) {
        return isUdpResponsive(ip, DHCP_PORT, buildDhcpDiscover());
    }

    /**
     * mDNS: Multicast 224.0.0.251:5353.
     * Wir senden eine mDNS-Query und prüfen ob eine Antwort kommt.
     * Fallback: TCP/UDP 5353 offen.
     */
    private boolean isMdnsNode(String ip) {
        if (isTcpOpen(ip, MDNS_PORT)) return true;
        return sendMdnsQuery(ip);
    }

    private boolean isNtpServer(String ip) {
        return isUdpResponsive(ip, NTP_PORT, buildNtpRequest());
    }

    // ── DNS Query (UDP) ───────────────────────────────────────────────────

    /**
     * Sendet einen minimalen DNS-Query für "version.bind" (CHAOS/TXT).
     * Echter DNS-Server antwortet, andere Geräte antworten nicht.
     */
    private boolean sendDnsQuery(String ip) {
        try (DatagramSocket socket = new DatagramSocket()) {
            socket.setSoTimeout(TIMEOUT_MS);
            byte[] query = buildDnsQuery("version.bind", true);
            InetAddress addr = InetAddress.getByName(ip);
            socket.send(new DatagramPacket(query, query.length, addr, DNS_PORT));
            byte[] buf = new byte[512];
            socket.receive(new DatagramPacket(buf, buf.length));
            // Antwort empfangen → DNS-Server bestätigt
            return true;
        } catch (SocketTimeoutException e) {
            return false; // kein DNS-Server
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Minimaler DNS-Query.
     * @param name  Hostname (z.B. "version.bind")
     * @param chaos true = CHAOS-Klasse, false = IN-Klasse
     */
    private byte[] buildDnsQuery(String name, boolean chaos) {
        // ID=0x1337, QR=0 (Query), Opcode=0, RD=1
        byte[] header = {
                0x13, 0x37,  // ID
                0x01, 0x00,  // Flags: RD=1
                0x00, 0x01,  // QDCOUNT=1
                0x00, 0x00,  // ANCOUNT=0
                0x00, 0x00,  // NSCOUNT=0
                0x00, 0x00   // ARCOUNT=0
        };

        // Name kodieren
        String[] labels = name.split("\\.");
        ByteArrayOutputStream nameBytes = new ByteArrayOutputStream();
        for (String label : labels) {
            byte[] lb = label.getBytes(StandardCharsets.US_ASCII);
            nameBytes.write(lb.length);
            nameBytes.write(lb, 0, lb.length);
        }
        nameBytes.write(0x00); // End-of-Name

        // QTYPE=TXT(16), QCLASS=CHAOS(3) oder IN(1)
        byte qclass = chaos ? (byte) 0x03 : (byte) 0x01;
        byte[] qtype = {0x00, 0x10, 0x00, qclass};

        ByteArrayOutputStream out = new ByteArrayOutputStream();
        out.write(header, 0, header.length);
        byte[] nb = nameBytes.toByteArray();
        out.write(nb, 0, nb.length);
        out.write(qtype, 0, qtype.length);
        return out.toByteArray();
    }

    // ── DHCP Discover (UDP) ───────────────────────────────────────────────

    /**
     * Minimales DHCP-Discover-Paket.
     * Wird an den spezifischen Host gesendet (kein Broadcast) um Kollisionen zu vermeiden.
     */
    private byte[] buildDhcpDiscover() {
        byte[] pkt = new byte[300];
        pkt[0]  = 0x01; // BOOTREQUEST
        pkt[1]  = 0x01; // Ethernet
        pkt[2]  = 0x06; // Hardware address length
        pkt[3]  = 0x00; // Hops
        // XID (random)
        new Random().nextBytes(new byte[4]);
        pkt[4] = 0x39; pkt[5] = 0x03; pkt[6] = (byte)0xF3; pkt[7] = 0x26;
        // Flags: broadcast
        pkt[10] = (byte)0x80; pkt[11] = 0x00;
        // Magic cookie
        pkt[236] = 0x63; pkt[237] = (byte)0x82; pkt[238] = 0x53; pkt[239] = 0x63;
        // Option 53: DHCP Discover
        pkt[240] = 0x35; pkt[241] = 0x01; pkt[242] = 0x01;
        // End option
        pkt[243] = (byte)0xFF;
        return pkt;
    }

    // ── mDNS Query (UDP Multicast) ────────────────────────────────────────

    private boolean sendMdnsQuery(String ip) {
        try (MulticastSocket socket = new MulticastSocket()) {
            socket.setSoTimeout(TIMEOUT_MS);
            socket.setTimeToLive(1);
            byte[] query = buildDnsQuery("_services._dns-sd._udp.local", false);
            InetAddress mdnsGroup = InetAddress.getByName("224.0.0.251");
            socket.send(new DatagramPacket(query, query.length, mdnsGroup, MDNS_PORT));
            byte[] buf = new byte[512];
            DatagramPacket response = new DatagramPacket(buf, buf.length);
            socket.receive(response);
            // Prüfen ob Antwort von der gesuchten IP kommt
            return ip.equals(response.getAddress().getHostAddress());
        } catch (Exception e) {
            return false;
        }
    }

    // ── NTP Request (UDP) ─────────────────────────────────────────────────

    private byte[] buildNtpRequest() {
        byte[] pkt = new byte[48];
        pkt[0] = 0x1B; // LI=0, VN=3, Mode=3 (Client)
        return pkt;
    }

    // ── Generic UDP probe ─────────────────────────────────────────────────

    private boolean isUdpResponsive(String ip, int port, byte[] payload) {
        try (DatagramSocket socket = new DatagramSocket()) {
            socket.setSoTimeout(TIMEOUT_MS);
            InetAddress addr = InetAddress.getByName(ip);
            socket.send(new DatagramPacket(payload, payload.length, addr, port));
            byte[] buf = new byte[512];
            socket.receive(new DatagramPacket(buf, buf.length));
            return true;
        } catch (SocketTimeoutException e) {
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    // ── TCP helper ────────────────────────────────────────────────────────

    private boolean isTcpOpen(String ip, int port) {
        try (Socket s = new Socket()) {
            s.connect(new InetSocketAddress(ip, port), TIMEOUT_MS);
            return true;
        } catch (Exception e) {
            return false;
        }
    }
}

package main.java.networktool.logic.scan;

import main.java.networktool.logic.analysis.OsDetector;
import main.java.networktool.logic.analysis.OuiDatabase;
import main.java.networktool.model.HostResult;
import main.java.networktool.model.ScanResult;
import main.java.networktool.util.CIDRUtils;

import java.io.*;
import java.net.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.regex.*;

public final class NetworkHostScanner {

    private NetworkHostScanner() {}

    private static final int THREAD_COUNT = Math.min(64,
            Math.max(20, Runtime.getRuntime().availableProcessors() * 4));
    private static final int DNS_TIMEOUT  = 600;

    private static final Pattern MAC_PATTERN = Pattern.compile(
            "([0-9A-Fa-f]{2}[:\\-]){5}[0-9A-Fa-f]{2}");
    private static final Set<String> INVALID_MACS = Set.of(
            "00:00:00:00:00:00", "FF:FF:FF:FF:FF:FF");

    /** Scannt /24-Präfixe — nutzt ARP-Cache + ICMP. */
    public static List<HostResult> scan(List<String> subnets) {
        HostAliveChecker.warmCache();
        // ARP-Cache als zusätzliche Quelle: alle Hosts die ARP beantwortet haben
        Map<String, String> arpHosts = readArpCache(subnets);
        List<String> ips = mergeIps(expandSubnets(subnets), arpHosts.keySet());
        return scanIpList(ips, arpHosts);
    }

    /** Scannt einen CIDR-Block. */
    public static List<HostResult> scanCidr(String cidr) {
        HostAliveChecker.warmCache();
        List<String> ips = CIDRUtils.getAllIPs(cidr);
        return scanIpList(ips, Collections.emptyMap());
    }

    // ── ARP-Cache lesen ───────────────────────────────────────────────────

    /**
     * Liest den ARP-Cache und filtert auf die gewünschten Subnetze.
     * Gibt IP→MAC zurück.
     */
    private static Map<String, String> readArpCache(List<String> subnets) {
        Map<String, String> result = new LinkedHashMap<>();
        boolean isWin = System.getProperty("os.name", "").toLowerCase().contains("win");
        try {
            Process p = Runtime.getRuntime().exec(isWin ? "arp -a" : "arp -a -n");
            try (BufferedReader br = new BufferedReader(new InputStreamReader(p.getInputStream()))) {
                String line;
                while ((line = br.readLine()) != null) {
                    String[] entry = parseArpLine(line);
                    if (entry == null) continue;
                    String ip = entry[0], mac = entry[1];
                    if (subnets.stream().anyMatch(s -> ip.startsWith(s + ".")))
                        result.put(ip, mac);
                }
            }
        } catch (Exception ignored) {}
        System.out.println("[NetworkHostScanner] ARP-Cache: " + result.size() + " Hosts gefunden");
        return result;
    }

    private static String[] parseArpLine(String line) {
        try {
            Matcher ipM  = Pattern.compile("\\b(\\d{1,3}\\.){3}\\d{1,3}\\b").matcher(line);
            Matcher macM = MAC_PATTERN.matcher(line);
            if (!ipM.find() || !macM.find()) return null;
            String ip  = ipM.group();
            String mac = macM.group().toUpperCase().replace("-", ":");
            if (INVALID_MACS.contains(mac)) return null;
            if (mac.startsWith("FF:FF") || mac.startsWith("01:")) return null;
            if (ip.endsWith(".0") || ip.endsWith(".255")) return null;
            return new String[]{ip, mac};
        } catch (Exception e) { return null; }
    }

    private static List<String> expandSubnets(List<String> subnets) {
        List<String> ips = new ArrayList<>(subnets.size() * 254);
        for (String subnet : subnets)
            for (int i = 1; i < 255; i++)
                ips.add(subnet + "." + i);
        return ips;
    }

    /** Vereinigt ICMP-Scan-IPs und ARP-IPs ohne Duplikate. */
    private static List<String> mergeIps(List<String> scanIps, Set<String> arpIps) {
        Set<String> merged = new LinkedHashSet<>(scanIps);
        merged.addAll(arpIps);
        return new ArrayList<>(merged);
    }

    // ── Scan ──────────────────────────────────────────────────────────────

    private static List<HostResult> scanIpList(List<String> ips, Map<String, String> knownMacs) {
        System.out.println("Starte Scan: " + ips.size() + " Hosts, Threads: " + THREAD_COUNT);
        List<HostResult> found    = Collections.synchronizedList(new ArrayList<>());
        ScanProgress     progress = new ScanProgress(ips.size());
        ExecutorService  executor = Executors.newFixedThreadPool(THREAD_COUNT,
                r -> { Thread t = new Thread(r); t.setDaemon(true); return t; });

        for (String host : ips)
            executor.submit(() -> { scanHost(host, found, knownMacs); progress.step(); });

        executor.shutdown();
        try { executor.awaitTermination(5, TimeUnit.MINUTES); }
        catch (InterruptedException ignored) { Thread.currentThread().interrupt(); }

        // Hosts aus ARP-Cache die nicht per ICMP gefunden wurden, direkt hinzufügen
        Set<String> foundIps = new HashSet<>();
        found.forEach(h -> foundIps.add(h.ip));
        knownMacs.forEach((ip, mac) -> {
            if (!foundIps.contains(ip)) {
                String hostname = resolveHostname(ip);
                String os = detectOsFast(ip, hostname, mac);
                found.add(new HostResult(ip, buildDisplay(hostname, mac), os));
            }
        });

        persistToHistory(found);
        System.out.println("Scan abgeschlossen: " + found.size() + " Gerät(e) gefunden.");
        return found;
    }

    private static void scanHost(String ip, List<HostResult> found, Map<String, String> knownMacs) {
        try {
            boolean alive = HostAliveChecker.isAlive(ip) || knownMacs.containsKey(ip);
            if (!alive) return;
            String mac      = knownMacs.getOrDefault(ip, readMacFromArp(ip));
            String hostname = resolveHostname(ip);
            String os       = detectOsFast(ip, hostname, mac);
            found.add(new HostResult(ip, buildDisplay(hostname, mac), os));
        } catch (Exception ignored) {}
    }

    private static String detectOsFast(String ip, String hostname, String mac) {
        String fromHn = OsDetector.detectFromHostname(hostname, ip);
        if (fromHn != null) return fromHn;
        if (mac != null && mac.length() >= 8) {
            String vendor = OuiDatabase.lookup(mac.substring(0, 8));
            if (vendor != null) return vendor;
        }
        return "Unbekannt";
    }

    private static String resolveHostname(String ip) {
        String dns = dnsLookup(ip);
        if (dns != null) return dns;
        String nb = netbiosLookup(ip);
        if (nb != null && !nb.isBlank()) return nb;
        return "host-" + ip.replace('.', '-');
    }

    private static String dnsLookup(String ip) {
        String[] result = {null};
        Thread t = new Thread(() -> {
            try {
                String name = InetAddress.getByName(ip).getCanonicalHostName();
                if (!name.equals(ip)) result[0] = name;
            } catch (Exception ignored) {}
        });
        t.setDaemon(true);
        t.start();
        try { t.join(DNS_TIMEOUT); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        return result[0];
    }

    private static String netbiosLookup(String ip) {
        boolean win = System.getProperty("os.name", "").toLowerCase().contains("win");
        try {
            String[] cmd = win ? new String[]{"nbtstat", "-A", ip} : new String[]{"nmblookup", "-A", ip};
            Process p = Runtime.getRuntime().exec(cmd);
            try (BufferedReader br = new BufferedReader(new InputStreamReader(p.getInputStream()))) {
                String line;
                while ((line = br.readLine()) != null) {
                    String name = parseNetbiosLine(line, win);
                    if (name != null) { p.destroy(); return name; }
                }
            }
            p.destroy();
        } catch (Exception ignored) {}
        return null;
    }

    private static String parseNetbiosLine(String line, boolean isWin) {
        if (line == null || line.isBlank()) return null;
        if (isWin) {
            String t = line.trim();
            if (t.contains("<00>") && !t.contains("__MSBROWSE__") && !t.startsWith("MAC")) {
                String[] parts = t.split("\\s+");
                if (parts.length > 0 && parts[0].length() > 1) return parts[0].trim();
            }
        } else {
            if (line.contains("name=") && line.contains("<0x0>")) {
                int s = line.indexOf("name=") + 5, e = line.indexOf('<', s);
                if (e > s) return line.substring(s, e).trim();
            }
        }
        return null;
    }

    static String readMacFromArp(String ip) {
        boolean win = System.getProperty("os.name", "").toLowerCase().contains("win");
        String[][] cmds = win
                ? new String[][]{{"arp", "-a", ip}, {"arp", "-a"}}
                : new String[][]{{"arp", "-n", ip}, {"arp", "-a", "-n"}, {"arp", "-a"}};
        for (String[] cmd : cmds) {
            String mac = queryArp(cmd, ip);
            if (mac != null) return mac;
        }
        return null;
    }

    private static String queryArp(String[] cmd, String targetIp) {
        try {
            Process p = Runtime.getRuntime().exec(cmd);
            try (BufferedReader br = new BufferedReader(new InputStreamReader(p.getInputStream()))) {
                String line;
                while ((line = br.readLine()) != null) {
                    if (!line.contains(targetIp)) continue;
                    String[] entry = parseArpLine(line);
                    if (entry != null) { p.destroy(); return entry[1]; }
                }
            }
            p.destroy();
        } catch (Exception ignored) {}
        return null;
    }

    private static void persistToHistory(List<HostResult> found) {
        if (found.isEmpty()) return;
        List<ScanResult> sr = found.stream()
                .map(h -> new ScanResult(h.ip, h.hostname, h.ports, h.os))
                .toList();
        ScanHistory.getInstance().add("Lokaler Scan", sr);
    }

    private static String buildDisplay(String hostname, String mac) {
        return mac != null && !mac.isBlank()
                ? hostname + " [" + mac + "]"
                : hostname;
    }
}

package networktool.logic.scan;

import networktool.logic.analysis.OsDetector;
import networktool.logic.analysis.OuiDatabase;
import networktool.model.HostResult;
import networktool.model.ScanResult;
import networktool.util.CIDRUtils;

import java.io.*;
import java.net.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.regex.*;

public final class NetworkHostScanner {

    private NetworkHostScanner() {}

    private static final int THREAD_COUNT = Math.min(64,
            Math.max(20, Runtime.getRuntime().availableProcessors() * 4));
    private static final int DNS_TIMEOUT  = 600;

    private static final Pattern MAC_PATTERN = Pattern.compile(
            "([0-9A-Fa-f]{2}[:\\-]){5}[0-9A-Fa-f]{2}");
    private static final Set<String> INVALID_MACS = Set.of(
            "00:00:00:00:00:00", "FF:FF:FF:FF:FF:FF");

    /** Scannt /24-Präfixe — nutzt ARP-Cache + ICMP. */
    public static List<HostResult> scan(List<String> subnets) {
        HostAliveChecker.warmCache();
        // ARP-Cache als zusätzliche Quelle: alle Hosts die ARP beantwortet haben
        Map<String, String> arpHosts = readArpCache(subnets);
        List<String> ips = mergeIps(expandSubnets(subnets), arpHosts.keySet());
        return scanIpList(ips, arpHosts);
    }

    /** Scannt einen CIDR-Block. */
    public static List<HostResult> scanCidr(String cidr) {
        HostAliveChecker.warmCache();
        List<String> ips = CIDRUtils.getAllIPs(cidr);
        return scanIpList(ips, Collections.emptyMap());
    }

    // ── ARP-Cache lesen ───────────────────────────────────────────────────

    /**
     * Liest den ARP-Cache und filtert auf die gewünschten Subnetze.
     * Gibt IP→MAC zurück.
     */
    private static Map<String, String> readArpCache(List<String> subnets) {
        Map<String, String> result = new LinkedHashMap<>();
        boolean isWin = System.getProperty("os.name", "").toLowerCase().contains("win");
        try {
            Process p = Runtime.getRuntime().exec(isWin ? "arp -a" : "arp -a -n");
            try (BufferedReader br = new BufferedReader(new InputStreamReader(p.getInputStream()))) {
                String line;
                while ((line = br.readLine()) != null) {
                    String[] entry = parseArpLine(line);
                    if (entry == null) continue;
                    String ip = entry[0], mac = entry[1];
                    if (subnets.stream().anyMatch(s -> ip.startsWith(s + ".")))
                        result.put(ip, mac);
                }
            }
        } catch (Exception ignored) {}
        System.out.println("[NetworkHostScanner] ARP-Cache: " + result.size() + " Hosts gefunden");
        return result;
    }

    private static String[] parseArpLine(String line) {
        try {
            Matcher ipM  = Pattern.compile("\\b(\\d{1,3}\\.){3}\\d{1,3}\\b").matcher(line);
            Matcher macM = MAC_PATTERN.matcher(line);
            if (!ipM.find() || !macM.find()) return null;
            String ip  = ipM.group();
            String mac = macM.group().toUpperCase().replace("-", ":");
            if (INVALID_MACS.contains(mac)) return null;
            if (mac.startsWith("FF:FF") || mac.startsWith("01:")) return null;
            if (ip.endsWith(".0") || ip.endsWith(".255")) return null;
            return new String[]{ip, mac};
        } catch (Exception e) { return null; }
    }

    private static List<String> expandSubnets(List<String> subnets) {
        List<String> ips = new ArrayList<>(subnets.size() * 254);
        for (String subnet : subnets)
            for (int i = 1; i < 255; i++)
                ips.add(subnet + "." + i);
        return ips;
    }

    /** Vereinigt ICMP-Scan-IPs und ARP-IPs ohne Duplikate. */
    private static List<String> mergeIps(List<String> scanIps, Set<String> arpIps) {
        Set<String> merged = new LinkedHashSet<>(scanIps);
        merged.addAll(arpIps);
        return new ArrayList<>(merged);
    }

    // ── Scan ──────────────────────────────────────────────────────────────

    private static List<HostResult> scanIpList(List<String> ips, Map<String, String> knownMacs) {
        System.out.println("Starte Scan: " + ips.size() + " Hosts, Threads: " + THREAD_COUNT);
        List<HostResult> found    = Collections.synchronizedList(new ArrayList<>());
        ScanProgress     progress = new ScanProgress(ips.size());
        ExecutorService  executor = Executors.newFixedThreadPool(THREAD_COUNT,
                r -> { Thread t = new Thread(r); t.setDaemon(true); return t; });

        for (String host : ips)
            executor.submit(() -> { scanHost(host, found, knownMacs); progress.step(); });

        executor.shutdown();
        try { executor.awaitTermination(5, TimeUnit.MINUTES); }
        catch (InterruptedException ignored) { Thread.currentThread().interrupt(); }

        // Hosts aus ARP-Cache die nicht per ICMP gefunden wurden, direkt hinzufügen
        Set<String> foundIps = new HashSet<>();
        found.forEach(h -> foundIps.add(h.ip));
        knownMacs.forEach((ip, mac) -> {
            if (!foundIps.contains(ip)) {
                String hostname = resolveHostname(ip);
                String os = detectOsFast(ip, hostname, mac);
                found.add(new HostResult(ip, buildDisplay(hostname, mac), os));
            }
        });

        persistToHistory(found);
        System.out.println("Scan abgeschlossen: " + found.size() + " Gerät(e) gefunden.");
        return found;
    }

    private static void scanHost(String ip, List<HostResult> found, Map<String, String> knownMacs) {
        try {
            boolean alive = HostAliveChecker.isAlive(ip) || knownMacs.containsKey(ip);
            if (!alive) return;
            String mac      = knownMacs.getOrDefault(ip, readMacFromArp(ip));
            String hostname = resolveHostname(ip);
            String os       = detectOsFast(ip, hostname, mac);
            found.add(new HostResult(ip, buildDisplay(hostname, mac), os));
        } catch (Exception ignored) {}
    }

    private static String detectOsFast(String ip, String hostname, String mac) {
        String fromHn = OsDetector.detectFromHostname(hostname, ip);
        if (fromHn != null) return fromHn;
        if (mac != null && mac.length() >= 8) {
            String vendor = OuiDatabase.lookup(mac.substring(0, 8));
            if (vendor != null) return vendor;
        }
        return "Unbekannt";
    }

    private static String resolveHostname(String ip) {
        String dns = dnsLookup(ip);
        if (dns != null) return dns;
        String nb = netbiosLookup(ip);
        if (nb != null && !nb.isBlank()) return nb;
        return "host-" + ip.replace('.', '-');
    }

    private static String dnsLookup(String ip) {
        String[] result = {null};
        Thread t = new Thread(() -> {
            try {
                String name = InetAddress.getByName(ip).getCanonicalHostName();
                if (!name.equals(ip)) result[0] = name;
            } catch (Exception ignored) {}
        });
        t.setDaemon(true);
        t.start();
        try { t.join(DNS_TIMEOUT); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        return result[0];
    }

    private static String netbiosLookup(String ip) {
        boolean win = System.getProperty("os.name", "").toLowerCase().contains("win");
        try {
            String[] cmd = win ? new String[]{"nbtstat", "-A", ip} : new String[]{"nmblookup", "-A", ip};
            Process p = Runtime.getRuntime().exec(cmd);
            try (BufferedReader br = new BufferedReader(new InputStreamReader(p.getInputStream()))) {
                String line;
                while ((line = br.readLine()) != null) {
                    String name = parseNetbiosLine(line, win);
                    if (name != null) { p.destroy(); return name; }
                }
            }
            p.destroy();
        } catch (Exception ignored) {}
        return null;
    }

    private static String parseNetbiosLine(String line, boolean isWin) {
        if (line == null || line.isBlank()) return null;
        if (isWin) {
            String t = line.trim();
            if (t.contains("<00>") && !t.contains("__MSBROWSE__") && !t.startsWith("MAC")) {
                String[] parts = t.split("\\s+");
                if (parts.length > 0 && parts[0].length() > 1) return parts[0].trim();
            }
        } else {
            if (line.contains("name=") && line.contains("<0x0>")) {
                int s = line.indexOf("name=") + 5, e = line.indexOf('<', s);
                if (e > s) return line.substring(s, e).trim();
            }
        }
        return null;
    }

    static String readMacFromArp(String ip) {
        boolean win = System.getProperty("os.name", "").toLowerCase().contains("win");
        String[][] cmds = win
                ? new String[][]{{"arp", "-a", ip}, {"arp", "-a"}}
                : new String[][]{{"arp", "-n", ip}, {"arp", "-a", "-n"}, {"arp", "-a"}};
        for (String[] cmd : cmds) {
            String mac = queryArp(cmd, ip);
            if (mac != null) return mac;
        }
        return null;
    }

    private static String queryArp(String[] cmd, String targetIp) {
        try {
            Process p = Runtime.getRuntime().exec(cmd);
            try (BufferedReader br = new BufferedReader(new InputStreamReader(p.getInputStream()))) {
                String line;
                while ((line = br.readLine()) != null) {
                    if (!line.contains(targetIp)) continue;
                    String[] entry = parseArpLine(line);
                    if (entry != null) { p.destroy(); return entry[1]; }
                }
            }
            p.destroy();
        } catch (Exception ignored) {}
        return null;
    }

    private static void persistToHistory(List<HostResult> found) {
        if (found.isEmpty()) return;
        List<ScanResult> sr = found.stream()
                .map(h -> new ScanResult(h.ip, h.hostname, h.ports, h.os))
                .toList();
        ScanHistory.getInstance().add("Lokaler Scan", sr);
    }

    private static String buildDisplay(String hostname, String mac) {
        return mac != null && !mac.isBlank()
                ? hostname + " [" + mac + "]"
                : hostname;
    }
}

package main.java.networktool.logic.scan;

import main.java.networktool.filter.HostResultFilter;
import main.java.networktool.filter.HostResultPrinter;
import main.java.networktool.model.HostResult;

import java.net.*;
import java.util.*;

public final class NetworkInfo {

    private NetworkInfo() {}

    public static volatile boolean testMode = false;

    public static void showMinimalInfo() throws Exception {
        System.out.println("\n=== Minimale Netzwerkinfo ===");
        System.out.println("Gerätename: " + InetAddress.getLocalHost().getHostName());
        runScan(null, null);
    }

    public static void showFullInfo() throws Exception {
        System.out.println("\n=== Vollständige Netzwerkinfo ===");
        printAllInterfaces();
        runScan(null, null);
    }

    public static void scanWithFilter(String osFilter, String hostnameFilter) throws Exception {
        runScan(osFilter, hostnameFilter);
    }

    // ── private ───────────────────────────────────────────────────────────

    private static void printAllInterfaces() throws SocketException {
        Enumeration<NetworkInterface> ifaces = NetworkInterface.getNetworkInterfaces();
        while (ifaces.hasMoreElements()) {
            NetworkInterface ni = ifaces.nextElement();
            System.out.println("\nInterface: " + ni.getName()
                    + " | Up: " + ni.isUp() + " | Loopback: " + ni.isLoopback());
            Enumeration<InetAddress> addrs = ni.getInetAddresses();
            while (addrs.hasMoreElements())
                System.out.println("  IP: " + addrs.nextElement().getHostAddress());
        }
    }

    private static void runScan(String osFilter, String hostnameFilter) throws Exception {
        if (testMode) {
            HostResultPrinter.print(List.of(),
                    HostResultFilter.buildLabel(osFilter, hostnameFilter));
            return;
        }

        List<String> subnets = SubnetDetector.getAllSubnets();
        if (subnets.isEmpty()) {
            System.out.println("Kein gültiges IPv4-Subnetz gefunden.");
            return;
        }

        System.out.printf("Scanne %d /24-Subnetz(e)...%n", subnets.size());

        // Kein Timeout — scan läuft bis fertig oder Interrupt
        List<HostResult> found = NetworkHostScanner.scan(subnets);
        List<HostResult> filtered = HostResultFilter.filter(found, osFilter, hostnameFilter);
        HostResultPrinter.print(filtered, HostResultFilter.buildLabel(osFilter, hostnameFilter));
    }
}

