                + " Hosts erreichbar → voll scannen");
        return alive;
    }

    private static void scanIp(String ip, List<ScanResult> results) {
        try {
            if (!InetAddress.getByName(ip).isReachable(REACH_TIMEOUT)) return;
            String hostname          = resolveHostname(ip);
            Map<Integer, String> ports = PortScanner.scanSimple(ip, 0);
            String os                = OsDetector.detect(ip);
            results.add(new ScanResult(ip, hostname, ports, os));
        } catch (Exception ignored) {}
    }

    private static String resolveHostname(String ip) {
        String[] result = {ip};
        Thread t = new Thread(() -> {
            try {
                String name = InetAddress.getByName(ip).getCanonicalHostName();
                if (name != null && !name.equals(ip)) result[0] = name;
            } catch (Exception ignored) {}
        });
        t.setDaemon(true);
        t.start();
        try { t.join(800); } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        return result[0];
    }
}

// src/main/java/networktool/security/AuditLogger.java
package main.java.networktool.security;

import java.nio.file.Path;
import java.util.*;
import java.util.concurrent.*;

public final class AuditLogger {

    private static final class Holder {
        static final AuditLogger INSTANCE = new AuditLogger();
    }
    public static AuditLogger getInstance() { return Holder.INSTANCE; }

    private volatile AuditLogFile    logFile;
    private volatile ExecutorService writer = newWriter();

    private AuditLogger() {}

    public void init(Path dataDir) {
        flushAndShutdown();
        this.logFile = new AuditLogFile(dataDir);
        this.writer  = newWriter();
    }

    // ── Schreiben ─────────────────────────────────────────────────────────

    public void log(String action) { log(action, ""); }

    public void log(String action, String detail) {
        if (logFile == null) return;
        String user  = currentUser();
        String ts    = AuditLogFile.nowFormatted();
        AuditLogEntry entry = new AuditLogEntry(ts, user, sanitize(action), sanitize(detail));
        writer.submit(() -> logFile.append(entry));
    }

    // ── Lesen ─────────────────────────────────────────────────────────────

    public List<AuditLogEntry> readRecent(int maxLines) {
        flush();
        if (logFile == null) return Collections.emptyList();
        return logFile.readRecent(maxLines);
    }

    public List<AuditLogEntry> readByUser(String username) {
        if (username == null) return Collections.emptyList();
        return readRecent(AuditLogFile.MAX_LINES).stream()
                .filter(e -> username.equalsIgnoreCase(e.user()))
                .toList();
    }

    // ── Löschen ───────────────────────────────────────────────────────────

    public void clear() {
        if (!isCurrentUserAdmin())
            throw new SecurityException("clear() erfordert Admin-Rechte.");
        flush();
        if (logFile == null) return;
        logFile.clear();
        log("AUDIT_LOG_CLEARED");
    }

    public void clearInternal(Path dataDir) {
        new AuditLogFile(dataDir).clear();
    }

    public void flush() {
        ExecutorService w = writer;
        if (w == null || w.isShutdown()) return;
        try {
            Future<?> f = w.submit(() -> {});
            f.get(3, TimeUnit.SECONDS);
        } catch (Exception ignored) {}
    }

    public void shutdown() {
        flush();          // wait for pending writes first
        flushAndShutdown();
        writer = newWriter();
    }

    // ── Legacy ────────────────────────────────────────────────────────────

    public static AuditLogEntry parse(String line) { return AuditLogFile.parse(line); }

    // ── Intern ────────────────────────────────────────────────────────────

    private void flushAndShutdown() {
        ExecutorService w = writer;
        if (w == null) return;
        try {
            w.shutdown();
            w.awaitTermination(3, TimeUnit.SECONDS);
        } catch (Exception ignored) {}
    }

    private static ExecutorService newWriter() {
        return Executors.newSingleThreadExecutor(r -> {
            Thread t = new Thread(r, "AuditLogger");
            t.setDaemon(true);
            return t;
        });
    }

    private static String currentUser() {
        String u = UserAuth.getInstance().getCurrentUser();
        return u != null ? u : "system";
    }

    private static boolean isCurrentUserAdmin() {
        String role = UserAuth.getInstance().getCurrentRole();
        return "admin".equals(role != null ? role.toLowerCase() : "");
    }

    private static String sanitize(String s) {
        if (s == null) return "";
        return s.replace("\t", " ").replace("\n", " ").replace("\r", "");
    }

    @Deprecated
    public static final class LogEntry {
        public final String timestamp, user, action, detail;
        public LogEntry(String timestamp, String user, String action, String detail) {
            this.timestamp = timestamp; this.user = user;
            this.action = action; this.detail = detail != null ? detail : "";
        }
        public static LogEntry from(AuditLogEntry e) {
            return new LogEntry(e.timestamp(), e.user(), e.action(), e.detail());
        }
    }
}

// src/main/java/networktool/security/AuditLogger.java
package main.java.networktool.security;

import java.nio.file.Path;
import java.util.*;
import java.util.concurrent.*;
import java.util.logging.Logger;
import java.util.logging.Level;

public final class AuditLogger {

    private static final class Holder {
        static final AuditLogger INSTANCE = new AuditLogger();
    }
    public static AuditLogger getInstance() { return Holder.INSTANCE; }

    private static final Logger LOGGER = Logger.getLogger(AuditLogger.class.getName());
    private volatile AuditLogFile    logFile;
    private volatile ExecutorService writer = newWriter();

    private AuditLogger() {}

    public void init(Path dataDir) {
        flushAndShutdown();
        this.logFile = new AuditLogFile(dataDir);
        this.writer  = newWriter();
    }

    // ── Schreiben ─────────────────────────────────────────────────────────

    public void log(String action) { log(action, ""); }

    public void log(String action, String detail) {
        if (logFile == null) return;
        String user  = currentUser();
        String ts    = AuditLogFile.nowFormatted();
        AuditLogEntry entry = new AuditLogEntry(ts, user, sanitize(action), sanitize(detail));
        writer.submit(() -> logFile.append(entry));
    }

    // ── Lesen ─────────────────────────────────────────────────────────────

    public List<AuditLogEntry> readRecent(int maxLines) {
        flush();
        if (logFile == null) return Collections.emptyList();
        return logFile.readRecent(maxLines);
    }

    public List<AuditLogEntry> readByUser(String username) {
        if (username == null) return Collections.emptyList();
        return readRecent(AuditLogFile.MAX_LINES).stream()
                .filter(e -> username.equalsIgnoreCase(e.user()))
                .toList();
    }

    // ── Löschen ───────────────────────────────────────────────────────────

    public void clear() {
        if (!isCurrentUserAdmin())
            throw new SecurityException("clear() erfordert Admin-Rechte.");
        flush();
        if (logFile == null) return;
        logFile.clear();
        log("AUDIT_LOG_CLEARED");
    }

    public void clearInternal(Path dataDir) {
        new AuditLogFile(dataDir).clear();
    }

    public void flush() {
        ExecutorService w = writer;
        if (w == null || w.isShutdown()) return;
        try {
            Future<?> f = w.submit(() -> {});
            f.get(3, TimeUnit.SECONDS);
        } catch (Exception ignored) {}
    }

    public void shutdown() {
        flush();          // wait for pending writes first
        flushAndShutdown();
        writer = newWriter();
    }

    // ── Legacy ────────────────────────────────────────────────────────────

    public static AuditLogEntry parse(String line) { return AuditLogFile.parse(line); }

    // ── Intern ────────────────────────────────────────────────────────────

    private void flushAndShutdown() {
        ExecutorService w = writer;
        if (w == null) return;
        try {
            w.shutdown();
            w.awaitTermination(3, TimeUnit.SECONDS);
        } catch (InterruptedException interruptedException) {
            LOGGER.log(Level.FINE, "ExecutorService termination interrupted", interruptedException);
            Thread.currentThread().interrupt();
        } catch (Exception exception) {
            LOGGER.log(Level.WARNING, "Error shutting down AuditLogger", exception);
        }
    }

    private static ExecutorService newWriter() {
        return Executors.newSingleThreadExecutor(r -> {
            Thread t = new Thread(r, "AuditLogger");
            t.setDaemon(true);
            return t;
        });
    }

    private static String currentUser() {
        String u = UserAuth.getInstance().getCurrentUser();
        return u != null ? u : "system";
    }

    private static boolean isCurrentUserAdmin() {
        String role = UserAuth.getInstance().getCurrentRole();
        return "admin".equals(role != null ? role.toLowerCase() : "");
    }

    private static String sanitize(String s) {
        if (s == null) return "";
        return s.replace("\t", " ").replace("\n", " ").replace("\r", "");
    }

    @Deprecated
    public static final class LogEntry {
        public final String timestamp, user, action, detail;
        public LogEntry(String timestamp, String user, String action, String detail) {
            this.timestamp = timestamp; this.user = user;
            this.action = action; this.detail = detail != null ? detail : "";
        }
        public static LogEntry from(AuditLogEntry e) {
            return new LogEntry(e.timestamp(), e.user(), e.action(), e.detail());
        }
    }
}

package main.java.networktool.security;

import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.PBEKeySpec;
import java.nio.file.Path;
import java.security.*;
import java.util.*;

public final class UserAuth {

    private static final class Holder { static final UserAuth INSTANCE = new UserAuth(); }
    public static UserAuth getInstance() { return Holder.INSTANCE; }

    private static final int    ITERATIONS = 310_000;
    private static final int    KEY_LEN    = 256;
    private static final int    SALT_LEN   = 32;
    private static final String ALGO       = "PBKDF2WithHmacSHA256";

    private Path dataDir;
    private volatile String currentUser;

    private UserAuth() {}

    public synchronized void init(Path dir) {
        this.dataDir = dir;
    }

    // ── Public API ────────────────────────────────────────────────────────

    public boolean hasUsers() {
        return dataDir != null && !UserAuthPersistence.load(dataDir).isEmpty();
    }

    public synchronized boolean createUser(String username, String password) {
        if (isBlank(username) || isBlank(password) || password.length() < 4) return false;
        String canonical = username.trim().toLowerCase();
        List<Map<String, String>> users = UserAuthPersistence.load(dataDir);
        if (users.stream().anyMatch(u -> canonical.equals(u.get("username")))) return false;
        try {
            byte[] salt = generateSalt();
            Map<String, String> entry = new LinkedHashMap<>();
            entry.put("username", canonical);
            entry.put("salt",     Base64.getEncoder().encodeToString(salt));
            entry.put("hash",     hash(password, salt));
            entry.put("role",     users.isEmpty() ? "admin" : "user");
            users.add(entry);
            UserAuthPersistence.save(dataDir, users);
            return true;
        } catch (Exception e) {
            System.err.println("[UserAuth] createUser: " + e.getMessage());
            return false;
        }
    }

    public synchronized boolean authenticate(String username, String password) {
        if (username == null || password == null) return false;
        String canonical = username.trim().toLowerCase();
        for (Map<String, String> u : UserAuthPersistence.load(dataDir)) {
            if (!canonical.equals(u.get("username"))) continue;
            try {
                byte[] salt = Base64.getDecoder().decode(u.get("salt"));
                if (MessageDigest.isEqual(
                        Base64.getDecoder().decode(u.get("hash")),
                        Base64.getDecoder().decode(hash(password, salt)))) {
                    currentUser = u.get("username");
                    return true;
                }
            } catch (Exception e) {
                System.err.println("[UserAuth] authenticate: " + e.getMessage());
            }
            return false;
        }
        return false;
    }

    public boolean isAdmin() {
        if (currentUser == null) return false;
        return UserAuthPersistence.load(dataDir).stream()
                .filter(u -> currentUser.equals(u.get("username")))
                .anyMatch(u -> "admin".equals(u.get("role")));
    }

    public String getCurrentRole() {
        if (currentUser == null) return "user";
        return UserAuthPersistence.load(dataDir).stream()
                .filter(u -> currentUser.equals(u.get("username")))
                .map(u -> u.getOrDefault("role", "user"))
                .findFirst().orElse("user");
    }

    public synchronized boolean changePassword(String username, String oldPw, String newPw) {
        if (!authenticate(username, oldPw) || isBlank(newPw) || newPw.length() < 4) return false;
        String canonical = username.trim().toLowerCase();
        List<Map<String, String>> users = UserAuthPersistence.load(dataDir);
        for (Map<String, String> u : users) {
            if (!canonical.equals(u.get("username"))) continue;
            try {
                byte[] salt = generateSalt();
                u.put("salt", Base64.getEncoder().encodeToString(salt));
                u.put("hash", hash(newPw, salt));
                UserAuthPersistence.save(dataDir, users);
                return true;
            } catch (Exception e) { return false; }
        }
        return false;
    }

    public synchronized boolean deleteUser(String username, String password) {
        if (!authenticate(username, password)) return false;
        String canonical = username.trim().toLowerCase();
        List<Map<String, String>> users = UserAuthPersistence.load(dataDir);
        if (users.size() <= 1) return false;
        users.removeIf(u -> canonical.equals(u.get("username")));
        UserAuthPersistence.save(dataDir, users);
        if (canonical.equals(currentUser)) currentUser = null;
        return true;
    }

    public void   logout()         { currentUser = null; }
    public String getCurrentUser() { return currentUser; }

    public List<String> listUsernames() {
        List<String> names = new ArrayList<>();
        UserAuthPersistence.load(dataDir).forEach(u -> names.add(u.get("username")));
        return Collections.unmodifiableList(names);
    }

    // ── Crypto ────────────────────────────────────────────────────────────

    private static String hash(String password, byte[] salt) throws Exception {
        SecretKeyFactory f = SecretKeyFactory.getInstance(ALGO);
        PBEKeySpec spec = new PBEKeySpec(password.toCharArray(), salt, ITERATIONS, KEY_LEN);
        byte[] key = f.generateSecret(spec).getEncoded();
        spec.clearPassword();
        return Base64.getEncoder().encodeToString(key);
    }

    private static byte[] generateSalt() {
        byte[] s = new byte[SALT_LEN];
        new SecureRandom().nextBytes(s);
        return s;
    }

    // Used by AuditLogger (same package)
    static String extractStr(String json, String field) {
        return UserAuthPersistence.extractStr(json, field);
    }

    private static boolean isBlank(String s) { return s == null || s.isBlank(); }
}

